template<class T> LVlistIterator<T>::LVlistIterator(LVlist<T> *pMotherLVlist)
: m_pMotherLVlist(pMotherLVlist)
{
	if (m_pMotherLVlist != 0) {
		m_pIter = m_pMotherLVlist->m_pRoot;
	} else {
		m_pIter = 0;
	}
}

