#include <cstring>


/*
 * This hack is necessary because:
 *
 * - Visual C++ doesn't support std::map<_K,_V>::at().
 *
 * - The AttributeMap formal parameter is always const (and rightly so!)
 * 
 * - We can't use [] because it is not const.
 *
 * - Hence, we need another method.  This seems cleanest.
 *
 */
std::string getAttribute(const AttributeMap& attrs, const std::string& key) throw(QDException)
{
	AttributeMap::const_iterator ci = attrs.find(key);
	if (ci == attrs.end()) {
		throw QDException("Could not find attribute with name '" + key + "'");
	} else {
		return ci->second;
	}
}






const std::string QDParser::NOTAG = "<>";

std::string QDParser::state2string(eQDStates e)
{
	if (e == TEXT) {
		return "TEXT";
	} else if (e == ENTITY) {
		return "ENTITY";
	} else if (e == OPEN_TAG) {
		return "OPEN_TAG";
	} else if (e == CLOSE_TAG) {
		return "CLOSE_TAG";
	} else if (e == START_TAG) {
		return "START_TAG";
	} else if (e == ATTRIBUTE_LVALUE) {
		return "ATTRIBUTE_LVALUE";
	} else if (e == ATTRIBUTE_EQUAL) {
		return "ATTRIBUTE_EQUAL";
	} else if (e == ATTRIBUTE_RVALUE) {
		return "ATTRIBUTE_RVALUE";
	} else if (e == QUOTE) {
		return "QUOTE";
	} else if (e == IN_TAG) {
		return "IN_TAG";
	} else if (e == SINGLE_TAG) {
		return "SINGLE_TAG";
	} else if (e == COMMENT) {
		return "COMMENT";
	} else if (e == DONE) {
		return "DONE";
	} else if (e == DOCTYPE) {
		return "DOCTYPE";
	} else if (e == IN_XMLDECLARATION) {
		return "IN_XMLDECLARATION";
	} else if (e == BEFORE_XMLDECLARATION) {
		return "BEFORE_XMLDECLARATION";
	} else if (e == OPEN_XMLDECLARATION) {
		return "OPEN_XMLDECLARATION";
	} else if (e == CDATA) {
		return "CDATA";
	} else {
		std::ostringstream str;
		str << "Unknown state: " << (int) e;
		throw QDException(str.str());
	}
}
	


void QDParser::parse(QDDocHandler *pDH, std::istream *pStream) throw(QDException) 
{
	bot = tok = ptr = cur = pos = lim = top = eof = 0;
	m_pInStream = pStream;
	m_pDH = pDH;
	m_tag_depth = 0;
	eQDStates state = BEFORE_XMLDECLARATION;
	m_encoding = kCSUTF8; // This is the default for XML
	m_tag_name = NOTAG;
	m_line = 1;
	m_column = 0;
	m_pDH->startDocument();
	m_end_of_line = false;

	char c = getNextChar();
	int nc = (int) c;

	while (hasMoreInput()) {
		//std::cerr << "UP200: state = " << state2string(state) << ", c = '" << c << "'" << std::endl;

		switch (state) {
		case TEXT:
			// We are collecting text between tags.
			switch (nc) {
			case (int) '&':
				pushState(TEXT);
				m_entity.clear();
				state = ENTITY;
				break;
			case (int) '<':
				if (!m_text.empty()) {
					m_pDH->text(m_text);
					m_text.clear();
				}
				pushState(TEXT);
				state = START_TAG;
				m_tag_name.clear();
				break;
			default:
				m_text += c;
				break;
			}
			break;
		case QUOTE:
			switch (nc) {
			case (int) '\n':
			case (int) '\t':
				// See XML Spec section 3.3.3
				// on normalization.
				// '\r' isn't metioned here because
				// it is converted to '\n' by getNextChar().
				m_rvalue += ' ';
				break;
			case (int) '&':
				pushState(QUOTE);
				state = ENTITY;
				m_entity.clear();
				break;
			default:
				if (nc == (int) m_quote_char) {
					m_attributes.insert(AttributeMap::value_type(m_lvalue, m_rvalue));
					state = popState();
				} else {
					m_rvalue += c;
				}
				break;
			}
			break;
		case ATTRIBUTE_LVALUE:
			switch (nc) {
			case (int) '=':
				state = ATTRIBUTE_RVALUE;
				break;
			case ' ':
			case '\n':
			case '\r':
			case '\x0b':
			case '\f':
				state = ATTRIBUTE_EQUAL;
				break;
			default:
				m_lvalue += c;
				break;
			}
			break;
		case OPEN_TAG:
			switch (nc) {
			case (int) '/':
				state = SINGLE_TAG;
				break;
			case (int) '>':
				++m_tag_depth;
				m_pDH->startElement(m_tag_name, m_attributes);
				eraseAttributes();
				m_tag_name.clear();
				state = popState();
				break;
			case ' ':
			case '\n':
			case '\r':
			case '\x0b':
			case '\f':
				state = IN_TAG;
				break;
			default:
				m_tag_name += c;
				if (nc == (int) '-' && m_tag_name == "!--") {
					//pushState(TEXT);
					state = COMMENT;
				} else if (nc == (int) '[' && m_tag_name == "![CDATA[") {
					m_text.clear();
					//pushState(TEXT);
					state = CDATA;
				} else if (nc == (int) 'E' && m_tag_name == "!DOCTYPE") {
					//pushState(TEXT);
					state = DOCTYPE;
					m_text.clear();
					m_tag_name.clear();
				} 
				break;
			}
			break;
		case IN_TAG:
			switch (nc) {
			case (int) '/':
				state = SINGLE_TAG;
				break;
			case (int) '>':
				++m_tag_depth;
				m_pDH->startElement(m_tag_name, m_attributes);
				eraseAttributes();
				m_tag_name.clear();
				state = popState();
				break;
			case ' ':
			case '\n':
			case '\r':
			case '\x0b':
			case '\f':
				; // Eat up
				break;
			default:
				pushState(IN_TAG);
				state = ATTRIBUTE_LVALUE;
				m_lvalue = c;
				m_rvalue.clear();
				break;
			}
			break;
		case START_TAG:
			{
				// The last char was '<'. Now
				// find out whether we are doing <starttag>,
				// </endtag>, <!-- comment -->,
				// <!DOCTYPE, or <![CDATA
				eQDStates topState = popState();
				switch (nc) {
				case (int) '/':
					pushState(topState);
					state = CLOSE_TAG;
					break;
				case (int) '?':
					pushState(topState);
					state = OPEN_XMLDECLARATION;
					eraseAttributes();
					break;
				default:
					pushState(topState);
					state = OPEN_TAG;
					m_tag_name = c;
					eraseAttributes();
					break;
				}
			}
			break;
		case ATTRIBUTE_RVALUE:
			switch (nc) {
			case(int) '\'':
			case (int) '\"':
				m_quote_char = c;
				state = QUOTE;
				break;
			case ' ':
			case '\n':
			case '\r':
			case '\x0b':
			case '\f':
				; // Eat up
				break;
			default:
				except("Error while processing attribute: After =, there should only be whitespace or '\\'' or '\\\"'.");
				break;
			}
			break;
		case SINGLE_TAG:
			// We are have seen 
			// something like
			// <barefoot attr1="value" ... /
			// Now we need the final >
			if (nc != (int) '>') {
				except("While processing single tag: Expected > for tag: <" + m_tag_name + "/>");
			} else {
				m_pDH->startElement(m_tag_name, m_attributes);
				m_pDH->endElement(m_tag_name);
				if (m_tag_depth == 0) {
					state = DONE;
				} else {
					state = popState();
					m_tag_name.clear();
					eraseAttributes();
				}
			}
			break;
		case CLOSE_TAG:
			// We have seen '</'
			if (nc == (int) '>') {
				m_pDH->endElement(m_tag_name);
				state = popState();
				--m_tag_depth;
				if (m_tag_depth == 0) {
					state = DONE;
				}
				m_tag_name.clear();
			} else {
				m_tag_name += c;
			}
			
			break;
		case IN_XMLDECLARATION:
			// We are inside <?xml .... ?>
			if (nc == (int) '?') {
				c = getNextChar();
				nc = (int) c;
				if (nc != (int) '>') {
					except("XML declaration must end with '?>'");
				} else {
					if (m_attributes.find("encoding") != m_attributes.end()) {
						std::string strencoding = m_attributes["encoding"];
						eCharsets tmpcharset;
						if (string2charset(strencoding, tmpcharset)) {
							m_encoding = tmpcharset;
						} else {
							// Use UTF-8 if charset unknown.
							// FIXME: Should we do an exception?
							m_encoding = kCSUTF8;
						}
					} else {
						m_encoding = kCSUTF8;
					}

					state = TEXT;
				}
			} else if (myisspace(nc)) {
				; // Eat up
			} else {
				pushState(IN_XMLDECLARATION);
				state = ATTRIBUTE_LVALUE;
				m_lvalue = c;
				m_rvalue.clear();
			}
			break;
		case BEFORE_XMLDECLARATION:
			if (nc == (int) '<') {
				c = getNextChar();
				nc = (int) c;
				if (nc == (int) '?') {
					c = getNextChar();
					if (c != 'x') {
						except("Document must start with '<?x'. It does not.");
					}
					c = getNextChar();	
					if (c != 'm') {
						except("Document must start with '<?xm'. It does not.");
					}
					c = getNextChar();
					if (c != 'l') {
						except("Document must start with '<?xml'. It does not.");
					}
					c = getNextChar();
					if (!myisspace((int) c)) {
						except("Document must start with '<?xml' + <whitespace>. It does not.");
					}
					state = IN_XMLDECLARATION;
				} else {
					except("Document must start with <?; it does not.");
				}
			}
			break;
		case ATTRIBUTE_EQUAL:
			switch (nc) {
			case (int) '=':
				state = ATTRIBUTE_RVALUE;
				break;
			case ' ':
			case '\n':
			case '\r':
			case '\x0b':
			case '\f':
				; // Eat up
				break;
			default:
				except("Error while processing attribute: After lvalue, there should only be whitespace or '='.");
				break;
			}
			break;
		case ENTITY:
			if (nc == (int) ';') {
				state = popState();
				handle_entity(state);
			} else {
				m_entity += c;
			}
			break;
		case COMMENT:
			if (nc == (int) '>') {
				m_text += c;
				if (string_ends_with(m_text, "-->")) {
					m_pDH->comment(m_text);

					m_text.clear();
					state = popState();
				} else {
					; // Nothing to do
				}
			} else {
				m_text += c;
			}
			break;
		case CDATA:
			if (nc == (int) '>') {
				if (string_ends_with(m_text, "]]")) {
					m_pDH->text(m_text.substr(0, m_text.length() - 2));
					state = popState();
					m_text.clear();
				} else {
					m_text += c;
				}
			} else {
				m_text += c;
			}
			break;
		case DOCTYPE:
			m_tag_name += c;
			if (nc == (int) '<') {
				m_tag_name.clear();
			} else if (nc == (int) '-' && m_tag_name == "!--") {
				pushState(DOCTYPE);
				state = COMMENT;
			} else if (nc == (int) ']') {
				m_tag_name = c;
			} else if (nc == (int) '>') {
				if (m_tag_name == "]>") {
					// Is TEXT
					state = popState();
				}
			} else {
				; // Eat up
			}
			break;
		case DONE:
			eraseAttributes();
			m_pDH->endDocument();
			cleanUp();
			return;
			break;
		default:
			except(std::string("Error: Unknown state: ") + state2string(state));
		}

		// Read next char
		c = getNextChar();
		nc = (int) c;
	}
	
	if (state == DONE) {
		m_pDH->endDocument();
	} else {
		except("missing end tag");
	}
	eraseAttributes();
	cleanUp();
}
	
void QDParser::except(const std::string& s) throw(QDException)
{
	std::ostringstream ostr;
	ostr << s << " near line " << m_line << ", column " << m_column << '!' << std::endl;
	throw QDException(ostr.str());
}

void QDParser::handle_entity(eQDStates state) throw(QDException)
{
	if (!m_entity.empty() && m_entity[0] == '#') {
		long l = 0;
		if (m_entity.length() > 1
		    && (m_entity[1] == 'x' 
			|| m_entity[1] == 'X')) {
			std::string hexstring = m_entity.substr(2, std::string::npos);
			if (is_hex(hexstring)) {
				l = hex2long(hexstring);
			} else {
				except("Invalid hex-string in entity &" + m_entity + ";.");
			}
		} else {
			std::string decimalstring = m_entity.substr(1, std::string::npos);
			l = string2long(decimalstring);
		}

		if (m_encoding == kCSUTF8) {
			std::string utf8str;
			long2utf8(l, utf8str);
			std::string::size_type i;
			std::string::size_type utf8length = utf8str.length();
			for (i = 0; i < utf8length; ++i) {
				if (state == QUOTE) {
					m_rvalue += utf8str[i];
				} else {
					m_text += utf8str[i];
				}
			}
		} else {
			if (l <= 255) {
				if (state == QUOTE) {
					m_rvalue += (char) l;
				} else {
					m_text += (char) l;
				}
			} else {
				except("Entity &" + m_entity + "; out of range; document is non-UTF8, and so we can handle only single-byte data.");
			}
		}
	} else {
		char entity_char = '\0';
		if (m_entity == "lt") {
			entity_char = '<';
		} else if (m_entity == "gt") {
			entity_char = '>';
		} else if (m_entity == "amp") {
			entity_char = '&';
		} else if (m_entity == "quot") {
			entity_char = '"';
		} else if (m_entity == "apos") {
			entity_char = '\'';
		} else {
			except("Unknown entity: &"+m_entity+";");
		}
		
		if (state == QUOTE) {
			m_rvalue += entity_char;
		} else {
			m_text += entity_char;
		}
	}
}


char QDParser::getNextChar(void) throw(QDException)
{
	char c;
	if ((lim - cur) < 1) fillBuffer();
	c = *cur++;

	int nc = (int) c;

	
	if (nc == (int) '\r') {
		m_end_of_line = true;
		m_column = 0;
		++m_line;
		return '\n';
	} else if (nc == (int) '\n') {
		if (m_end_of_line) {
			// We have already read \r, and this is \n that follows.
			// \r returned \n, since we need to translate
			// all of \r\n, \r, and \n to \n 
			// (see Section 2.11 of the XML spec)
			// So now we return the next character, since this
			// method is called 'getNextChar()'.
			if (hasMoreInput()) {
				c = *cur++;
			}
			++m_column;
			m_end_of_line = false;
		} else {
			m_column = 0;
			++m_line;
		}
		return c;
	} else {
		m_end_of_line = false; // We might be doing a file with \r as the end-of-line marker.
		++m_column;
		return c;
	}
}

#define BSIZE   (1024*1024)


void QDParser::fillBuffer()
{
        if(!eof)
        {
                unsigned int cnt = tok - bot;
		/*
		std::cerr << "UP205: "
			  << " cnt = " << cnt 
			  << " tok = " << (void*) tok
			  << " bot = " << (void*) bot 
			  << " cur = " << (void*) cur
			  << " eof = " << (void*) eof 
			  << " ptr = " << (void*) ptr
			  << " lim = " << (void*) lim
			  << std::endl;
		*/
                if(cnt)
                {
                        memcpy(bot, tok, lim - tok);
                        tok = bot;
                        ptr -= cnt;
                        cur -= cnt;
                        pos -= cnt;
                        lim -= cnt;
                }
                if((top - lim) < BSIZE)
                {
                        char *buf = new char[(lim - bot) + BSIZE];
                        memcpy(buf, tok, lim - tok);
                        tok = buf;
                        ptr = &buf[ptr - bot];
                        cur = &buf[cur - bot];
                        pos = &buf[pos - bot];
                        lim = &buf[lim - bot];
                        top = &lim[BSIZE];
                        delete [] bot;
                        bot = buf;
                }
                m_pInStream->read(lim, BSIZE);
                if ((cnt = m_pInStream->gcount()) != BSIZE )
                {
                        eof = &lim[cnt]; *eof++ = '\0';
                }
                lim += cnt;
        }
}


QDParser::QDParser()
{
	bot = tok = ptr = cur = pos = lim = top = eof = 0;
}

QDParser::~QDParser()
{
	cleanUp();
}



