FeatureInfo::FeatureInfo(std::string name, id_d_t type,
   		   std::string default_value, bool is_computed) 
	: m_name(name), 
	  m_type(type), 
	  m_default_value(default_value), 
	  m_is_computed(is_computed)
{
}

FeatureInfo::FeatureInfo(const FeatureInfo& other)
{
  copyOther(other);
}

