inline void longlong2sz(long long l, char *szResult)
{
	// Build up string in reverse
	char *p = szResult;
	long long v = l;
	do {
		long long tmp = v;
		v /= 10;
		*p++ = "9876543210123456789" [9+(tmp - v*10)];
	} while (v);
	
	// Add negative sign at the end if necessary	
	if (l < 0) {
		*p++ = '-';
	}
	
	// Terminate string
	*p-- = '\0';
	
	// Reverse string
	char *q = szResult;
	while (q < p) {
		char swap_c = *p;
		*p-- = *q;
		*q++ = swap_c;
	}
}

