class IntegerList; // Forward declaration
class SetOfMonads; // Forward declaration


/** An EMdF value.
 *
 * Is a union of an id_d_t, a long, and a pointer to std::string.
 *
 * Also has an eEVkind member, showing what kind it is.
 */
class EMdFValue {
private:
#ifndef SWIG
  union {
    id_d_t m_id_d;
    long m_int;
    std::string *m_pString;
    IntegerList *m_pIntegerList;
    SetOfMonads *m_pSOM;
  } m_u;
  eEVkind m_kind;
#endif /* ndef SWIG */
public: 
  EMdFValue(); // Don't use unless you plan to = assign a new value later
  EMdFValue(const EMdFValue& other) throw(EmdrosException);
  EMdFValue(eEVkind kind, long i) throw(EmdrosException);
  EMdFValue(const std::string& str);
  EMdFValue(const SetOfMonads& som);
  EMdFValue(eEVkind kind, IntegerList* pIntegerList) throw(EmdrosException);
  ~EMdFValue();
  eEVkind getKind(void) const { return m_kind; };
  const std::string getString(void) const throw(EmdrosException);
  SetOfMonads getSOM(void) const throw(EmdrosException);
  id_d_t getID_D(void) const { return m_u.m_id_d; };
  long getInt(void) const { return m_u.m_int; };
  long getEnum(void) const { return m_u.m_int; };
  IntegerList *getIntegerList (void) const throw(EmdrosException);
  bool compare(const EMdFValue& other, eComparisonOp op) const throw(EmdrosException);
  std::string toString(void) const;
  void changeString(const std::string& newString) throw(EmdrosException);
#ifndef SWIG
  EMdFValue& operator=(const EMdFValue& other) throw(EmdrosException);
#endif /* ndef SWIG */
private:
  bool compareInt(const EMdFValue& other, eComparisonOp op) const throw(EmdrosException);
  bool compareString(const EMdFValue& other, eComparisonOp op) const throw(EmdrosException);
  bool compareListOfIntegerWithAtomicValue(const EMdFValue& other, eComparisonOp op) const throw(EmdrosException);
  bool compareSetOfMonads(const EMdFValue& other, eComparisonOp op) const throw(EmdrosException);
  void assign(const EMdFValue& other) throw(EmdrosException);
  void deleteContents() throw(EmdrosException);
};




#endif // EMDF_VALUE__H__

