JSONListElement::JSONListElement(JSONValue *pValue)
{
	m_pValue = pValue;
	m_pNext = 0;
}


JSONListElement::~JSONListElement()
{
	delete m_pValue;
	delete m_pNext;
}

void JSONListElement::destroyList(JSONListElement *pList)
{
	JSONListElement *pCur = pList;
	while (pCur != 0) {
		JSONListElement *pNext = pCur->m_pNext;
		pCur->m_pNext = 0;
		delete pCur;
		pCur = pNext;
	}
}






