/* 
** This function allocates a new parser.
** The only argument is a pointer to a function which works like
** malloc.
**
** Inputs:
** A pointer to the function used to allocate memory.
**
** Outputs:
** A pointer to a parser.  This pointer is used in subsequent calls
** to JSONParser and JSONParserFree.
*/
void *JSONParserAlloc(void *(*mallocProc)(size_t)){
  jsonyyParser *pParser;
  pParser = (jsonyyParser*)(*mallocProc)( (size_t)sizeof(jsonyyParser) );
  if( pParser ){
    pParser->jsonyyidx = -1;
#ifdef JSONYYTRACKMAXSTACKDEPTH
    pParser->jsonyyidxMax = 0;
#endif
#if JSONYYSTACKDEPTH<=0
    pParser->jsonyystack = NULL;
    pParser->jsonyystksz = 0;
    jsonyyGrowStack(pParser);
#endif
  }
  return pParser;
}

