class SQLiteEMdFConnection : public EMdFConnection {
 private:
	std::string m_db_name;
	bool m_bTransactionInProgress;
#if USE_SQLITE2
	sqlite *m_pDB;
	sqlite_vm *m_pVM;
#endif
	const char **m_pRow;
	int m_nNoOfFields;
 public:
	// Constructor and destructor
	SQLiteEMdFConnection(const std::string& db, const std::string& key);
	virtual ~SQLiteEMdFConnection();

	// Status of connection
	// Returns true on connection good, false on connection bad
	virtual bool connectionOk(void);
  
	// Executing SELECT
	virtual bool execSelect(const std::string& query);

	// Executing all others
	virtual bool execCommand(const std::string& query);

	// Get last error message
	// Returns true on error message available 
	// (even if it is "OK"), false on error 
	// message not available.
	virtual bool errorMessage(std::string& out);

	// Transactions
	virtual bool beginTransaction(void);
	virtual bool commitTransaction(void);
	virtual bool abortTransaction(void);

	// Field count
	// Returns -1 on no fields.
	virtual int getNoOfFields(void);

	int getLastInsertRowID(void) {
#if USE_SQLITE2
		if (m_pDB == 0) {
			return 0;
		} else {
			return sqlite_last_insert_rowid(m_pDB);
		}
#else
		return 0;
#endif
	}

	// Getting next tuple
	// Returns true on success, false on failure
	// On success, bMoreTuples tells us whether there are any more tuples.
	virtual bool getNextTuple(bool& bMoreTuples) {
#if USE_SQLITE2
		if (m_pDB == 0 || m_pVM == 0) {
			return false;
		} else {
			// Try until we don't get a BUSY result
			int result;
			while ((result = sqlite_step(m_pVM, &m_nNoOfFields, &m_pRow, NULL))
			       == SQLITE_BUSY) {
				// Busy-waiting
				for (int i = 0; i < 10000; i++) {
					;;
				}
			}
      
			if (result == SQLITE_ROW) {
				bMoreTuples = true;
				return true;
			} else if (result == SQLITE_DONE) {
				bMoreTuples = false;
				return true;
			} else if (result == SQLITE_ERROR) {
				bMoreTuples = false;
				return false;
			} else if (result == SQLITE_MISUSE) {
				appendLocalError("GetNetxTuple: result == SQLITE_MISUSE.");
				bMoreTuples = false;
				return false;
			} else {
				// We should not get any other return values than the above
				ASSERT_THROW(false, "Unknown SQLite result");
				// Just to fool the compiler into not giving a warning...
				return false;
			}
		}
#else
		return false;
#endif
	};

	// Is there a row in the local cache?
	// Must be called right after the query is done.
	virtual bool hasRow(void) const {
#ifdef USE_SQLITE2
		return m_pRow != 0;
#else
		return false;
#endif
	};

	// Tuple-access
	// First tuple is 0
	// First field is 0.
	virtual bool accessTuple(int field_no, 
				 bool& result) throw(EMdFNULLValueException) {
#if USE_SQLITE2
		if (m_pRow == 0) {
			return false; 
		} else {
			// Declare field
			const char *pField = m_pRow[field_no];

			// Check for NULL value
			if (pField == NULL) {
				// It was NULL.  Throw exception
				throw EMdFNULLValueException();
			} else {
				// It wasn't NULL.  Convert result
				result = char2bool(*pField);
			}
	
			// Return success      
			return true;
		}
#else
		return false;
#endif
	};

	virtual bool accessTuple(int field_no, 
				 long& result) throw(EMdFNULLValueException) {
#if USE_SQLITE2
		if (m_pRow == NULL) {
			// Return failure
			return false;
		} else {
			const char *pField = m_pRow[field_no];
			// Convert result
			// NOTE: The following is MUCH slower than strtol or atol.
			//std::string strtmp = pField;
			//std::istringstream mystringstream(strtmp);
			//mystringstream >> result;
	
			// Check for NULL value
			if (pField == NULL) {
				// It was NULL.  Throw exception
				throw EMdFNULLValueException();
			} else {
				// It wasn't NULL.  Convert result
				result = atol(pField);
			}
	
			// Return success      
			return true;
		}
#else
		return false;
#endif
	};

	virtual bool accessTuple(int field_no, 
				 std::string& result) throw(EMdFNULLValueException) {
#ifdef USE_SQLITE2
		if (m_pRow == 0) {
			return false;
		} else {
			const char *pField = m_pRow[field_no];

			// Check for NULL value
			if (pField == NULL) {
				// It was NULL.  Throw exception
				throw EMdFNULLValueException();
			} else {
				// It wasn't NULL.  Convert result
				result = pField;
			}
      
			// Return success
			return true;
		}
#else
		return false;
#endif
	};

	// Be done with a result set
	virtual void finalize(void);

	// UseDatabase
	virtual bool useDatabase(const std::string& database_name, const std::string& key) { return this->useDatabase(database_name, key, false); };
	bool useDatabase(const std::string& database_name, const std::string& key, bool bIsCreating);

 public:
	void get_last_insert_rowid(long& result /* out */);

	// Vacuum
	bool vacuum();

 protected:

 private:
	// Make the assignment operator and copy constructor private
	// because they are not supported.
	SQLiteEMdFConnection(const SQLiteEMdFConnection&);
	SQLiteEMdFConnection& operator=(const SQLiteEMdFConnection&);

	// Clean up
	void deleteDatabase(void);
};


