// Executing
/** Execute a SELECT SQL query.
 *
 * @internal
 *
 * @param query The SELECT query to execute.
 *
 * @return True on no DB error, false otherwise.
 *
 */
bool SQLiteEMdFConnection::execSelect(const std::string& query)
{
#if USE_SQLITE2
	if (m_pDB == 0)
		return false;
	else {
		// Write to log
#if EMDROS_LOGGING
		std::string log = "Starting query.\n" + query;
		LOG_WRITE_TIME("SQLiteEMdFConnection::execSelect", log);
#endif

		// Clear the Result Stucture if needed
		finalize();

		// Compile
		char *szError = NULL;
		if (sqlite_compile(m_pDB, query.c_str(), NULL, &m_pVM, &szError)
		    != SQLITE_OK) {
			// We did not succeed
			LOG_WRITE_TIME("SQLiteEMdFConnection::execSelect", "query compilation failed.");

			// Was there an error message?
			if (szError != NULL) {
				// Append error
				appendLocalError(std::string(szError));

				// Free error
				sqlite_freemem(szError);
			}

			// Return failure
			return false;
		}

		// Get first row
		bool bMoreTuples;
		if (!getNextTuple(bMoreTuples))
			return false;

		// Write to log
		LOG_WRITE_TIME("SQLiteEMdFConnection::execSelect", "Query finished.");

		// Return success
		return true;
	}
#else
	return false;
#endif
}


/** Execute a non-SELECT SQL statement.
 *
 * @internal
 *
 * This is used for all SQL queries other than SELECT queries.
 *
 * @param query The query to execute.
 *
 * @return True on no DB error, false otherwise.
 *
 */
bool SQLiteEMdFConnection::execCommand(const std::string& query)
{
#if USE_SQLITE2
	if (m_pDB == 0)
		return false;
	else {
		// Write to log
#if EMDROS_LOGGING
		std::string log = "Starting query.\n" + query;
		LOG_WRITE_TIME("SQLiteEMdFConnection::execCommand", log);
#endif

		// Clear the result stucture if needed
		finalize();

		// Compile
		int result;
		char *szError;
		while ((result = sqlite_exec(m_pDB, query.c_str(), NULL, NULL, &szError))
		       == SQLITE_BUSY) {
			// Busy-waiting
			for (int i = 0; i < 10000; i++) {
				;;
			}
		}

		if (result != SQLITE_OK) {
			// We did not succeed
			LOG_WRITE_TIME("SQLiteEMdFConnection::execCommand", "query failed.");

			// Was there an error message?
			if (szError != NULL) {
				// Append error
				appendLocalError(std::string(szError));

				// Free error
				free(szError);
			}

			// Return failure
			return false;
		}

		// Write to log
		LOG_WRITE_TIME("SQLiteEMdFConnection::execCommand", "Query finished.");

		// Return success
		return true;
	}
#else
	return false;
#endif
}


