// Transactions
/** Begin transaction.
 *
 * @internal
 *
 * @return True on transaction started, false otherwise.
 *
 */
bool SQLiteEMdFConnection::beginTransaction(void)
{
#if USE_SQLITE2
	if (m_pDB == 0)
		return false;
	else {
		if (m_bTransactionInProgress) {
			return false;
		} else {
			m_bTransactionInProgress = true;
			return execCommand("BEGIN");
		}
	}
#else
	return false;
#endif
}

/** Commit transaction.
 *
 * @internal
 *
 * @return True on transaction committed, false otherwise.
 *
 */
bool SQLiteEMdFConnection::commitTransaction(void)
{
#if USE_SQLITE2
	if (m_pDB == 0)
		return false;
	else {
		if (m_bTransactionInProgress) {
			m_bTransactionInProgress = false;
			return execCommand("COMMIT");
		} else {
			appendLocalError("commitTransaction: No transaction in progress.");
			return false;
		}
	}
#else
	return false;
#endif
}

/** Abort/RollBack transaction.
 *
 * @internal
 *
 * @return True on transaction aborted successfully, false otherwise.
 */
bool SQLiteEMdFConnection::abortTransaction(void)
{
#if USE_SQLITE2
	if (m_pDB == 0)
		return false;
	else {
		if (m_bTransactionInProgress) {
			m_bTransactionInProgress = false;
			return execCommand("ROLLBACK");
		} else {
			appendLocalError("abortTransaction: No transaction in progress.");
			return false;
		}
	}
#else
	return false;
#endif
}


