//
// It is necessary to do _wfopen on Windows, since fopen accepts a
// filename in the local code page, whereas what we give it is
// actually UTF-8 from wxWidgets.  Hence, we need to use a version of
// fopen which uses a wide char string, and then convert explicitly
// from UTF-8.
//
FILE *BPTfopen(const char *szFilePath, const char *szMode)
{
	FILE *pFILE = 0;
#if defined(WIN32) || defined(WIN64) || defined(__WIN32__) || defined(__WIN64__)
	const int BUFLENGTH = 8192;
	wchar_t filepath[BUFLENGTH];
	wchar_t mode[BUFLENGTH];
	int nResult = ::MultiByteToWideChar(CP_UTF8, 0, szFilePath, -1, filepath, BUFLENGTH);
	nResult = ::MultiByteToWideChar(CP_UTF8, 0, szMode, -1, mode, BUFLENGTH);	
#if defined(__MINGW32__) || defined(__MINGW64__)
	// MinGW doesn't have the secure version
	pFILE = _wfopen(filepath, mode);
#else
	// Visual Studio has the secure version
	_wfopen_s(&pFILE, filepath, mode);
#endif

#else
	pFILE = ::fopen(szFilePath, szMode);
#endif
	return pFILE;
}





