typedef unsigned int UINT;


UINT myrand(UINT seed, UINT a, UINT c)
{
	UINT result = seed;
	result = result * a + c;
	return result;
}


UINT myrand2(UINT seed, UINT a, UINT c)
{
	UINT result = seed, tmp, i;
	do {
		result = myrand(result, a, c);
	} while (result == 0);

	/* Skip some numbers in the sequence (security through obscurity). */

	/* Skip one, then ... */
	tmp = myrand(result, a, c);

	/* Get one which we'll use to ... */
	tmp = myrand(tmp, a, c);

	/* ... skip up to 15 random numbers based on the previous one. */
	for (i = 0; i < (tmp & 0x0000000f); ++i) {
		tmp = myrand(tmp, a, c);
	}

	result = myrand(tmp, a, c);
  
	return result;
}



void getAandC(UINT *pA, UINT *pC, UINT seed, UINT seedA, UINT seedC)
{
	UINT q, r, tmp, i;

	q = seed;
	do {
		q = myrand(q, seedA, seedC);
	} while (q >= (2U << 29) || q == 0);

	/* Skip some numbers in the sequence (security through obscurity). */

	/* Skip one, then ... */
	tmp = myrand(q, seedA, seedC);

	/* Get one which we'll use to ... */
	tmp = myrand(tmp, seedA, seedC);

	/* ... skip up to 7 random numbers based on the previous one. */
	for (i = 0; i < (tmp & 0x00000007); ++i) {
		tmp = myrand(tmp, seedA, seedC);
	}
	/* Skip one last one, just to make sure :-P ... */
	tmp = myrand(tmp, seedA, seedC);

	/* Now choose an appropriate r. */
	r = tmp;
	do {
		r = myrand(r, seedA, seedC);
	} while (r >= (2U << 30) || r == 0);

	/* And finally, calculate A and C. */
	*pA = 4*q + 1;
	*pC = 2*r + 1;
}






bool decode_codec_key3(const void *pKey, int nKey, unsigned int codec_key3[])
{
	int nResult;
	char *szKey = (char*) pKey;
	/* 4 pairs of 4 bytes split over 2 characters plus 2 characters for the 0x,
	   plus 7 separating spaces. */
#define NOOFCHARSINVALIDSCHEDULEDKEY (4*2*(4*2+2) + 7)
#define NOOFCHARSINVALIDSCHEDULINGKEY (56 / 8)
#define NOOFCHARSINVALIDSCHEDULINGKEYALTERNATIVEENCODING (2*(4*2+2) + 1)
	if (nKey == NOOFCHARSINVALIDSCHEDULEDKEY) {
		nResult = sscanf(szKey, "%x %x %x %x %x %x %x %x", 
				 &(codec_key3[0]),
				 &(codec_key3[1]),
				 &(codec_key3[2]),
				 &(codec_key3[3]),
				 &(codec_key3[4]),
				 &(codec_key3[5]),
				 &(codec_key3[6]),
				 &(codec_key3[7]));
		if (nResult == 8) {
			return true;
		} else {
			return false;
		}
	} else if (nKey == NOOFCHARSINVALIDSCHEDULINGKEYALTERNATIVEENCODING) {
		UINT s, t;
		nResult = sscanf(szKey, "%x %x",
				 &s,
				 &t);
		if (nResult == 2) {
			char szSchedulingKey[NOOFCHARSINVALIDSCHEDULINGKEY+1];
			szSchedulingKey[0] = s & 0xFF;
			szSchedulingKey[1] = (s >> 8) & 0xFF;
			szSchedulingKey[2] = (s >> 16) & 0xFF;
			szSchedulingKey[3] = (s >> 24) & 0xFF;
			szSchedulingKey[4] = t & 0xFF;
			szSchedulingKey[5] = (t >> 8) & 0xFF;
			szSchedulingKey[6] = (t >> 16) & 0xFF;
			szSchedulingKey[7] = '\0';
			return decode_codec_key3((const void*) szSchedulingKey, NOOFCHARSINVALIDSCHEDULINGKEY, codec_key3);
		} else {
			return false;
		}
	} else if (nKey == NOOFCHARSINVALIDSCHEDULINGKEY) {
		char szScheduledKey[NOOFCHARSINVALIDSCHEDULEDKEY+1];
		UINT a = 0, c = 0, q = 0, r = 0, seed = 0;
		UINT arrA[4];
		UINT arrC[4];
		q = (szKey[0]) | (szKey[5] << 8) | (szKey[2] << 16);
		r = (szKey[6]) | (szKey[3] << 8) | (szKey[4] << 16) | (szKey[1] << 24);
		a = 4*q + 1;
		c = 2*r + 1;
		seed = myrand(0xe717b9a6, a, c);
		getAandC(&(arrA[0]), &(arrC[0]), seed, a, c);
		seed = myrand2(seed, a, c);
		getAandC(&(arrA[1]), &(arrC[1]), seed, a, c);
		seed = myrand2(seed, a, c);
		getAandC(&(arrA[2]), &(arrC[2]), seed, a, c);
		seed = myrand2(seed, a, c);
		getAandC(&(arrA[3]), &(arrC[3]), seed, a, c);
		sprintf(szScheduledKey, 
			"0x%08x 0x%08x 0x%08x 0x%08x 0x%08x 0x%08x 0x%08x 0x%08x", 
			arrA[0], arrC[0], 
			arrA[1], arrC[1], 
			arrA[2], arrC[2], 
			arrA[3], arrC[3]);
		return decode_codec_key3((const void*) szScheduledKey, NOOFCHARSINVALIDSCHEDULEDKEY, codec_key3);
	} else {
		return false;
	}
}

bool BPTKeyIsOK(const std::string& key)
{
	unsigned int codec_key3[4*2];
	if (decode_codec_key3(key.c_str(), key.length(), codec_key3)) {
		return true;
	} else {
		return false;
	}
}

void useCodecOnPageData(void *pPageData, int pageNo, unsigned int codec_key3[])
{
	unsigned int i;

	/* The pointer to the input data. */
	unsigned int *p;
      
	/* Since we are going to use pCodecArg as an array of unsigned int,
	   we might as well cast it... */
	unsigned int *pCodecKey = codec_key3;
      
	/* Choose a seed for the pseudo-random stream of numbers
	 * to XOR with.
	 * This gives a very nice "hash" value which "looks"
	 * random to the eye (but I have not tested it for randomness...)
	 */
	unsigned int xor_value = ((pageNo << 24)
				  ^(pageNo << 16)
				  ^ pageNo
				  ^ (0x9b68a3ce >> (pageNo & 0x0f)));
      
      
	/* Find index at which to look for a and c in codec_key3. */
	unsigned int index = ((xor_value) & 0x03) * 2;
      
	/* multiplicator (a) and the increment (c). */
	unsigned int a, c;
      
	p = (unsigned int*) pPageData;
      
      
	/* Get the multiplicator (a) and the increment (c) from pCodecKey. */
	a = (pCodecKey)[index];
	c = (pCodecKey)[index+1];
      
      
	/* Iterate through page, encrypting/decrypting by doing
	 * XORs 4 bytes at a time, with a sequence of pseudo-random
	 * bytes, where the seed is given by the initial value of
	 * xor_value above.
	 */
	for (i = 0; i < ((Page::PageSize)/sizeof(unsigned int)); ++i) {
		/* XOR 4 bytes (one int) */
#if WORD_IS_BIGENDIAN
#define MYSWAB32(X) (((X & 0xff)<<24) | ((X & 0xff00)<<8) | ((X>>8) & 0xff00) | ((X>>24)&0xff))
		*p++ ^= MYSWAB32(xor_value);
#else
		*p++ ^= xor_value;
#endif
	      
		/* Get next pseudo-random number X */
		xor_value = xor_value * a + c;
	}
}



bool headerStartsWithMagic(unsigned char *pFirstPageData)
{
	if (pFirstPageData[0] == 'E'
	    && pFirstPageData[1] == 'M'
	    && pFirstPageData[2] == 'd'
	    && pFirstPageData[3] == 'F') {
		return true;
	} else {
		return false;
	}
}




LRUCache::LRUCache(int max_number_of_entries, PageCache *pParent)
	: m_cache_list(max_number_of_entries, LRUCacheListNode()),
	  m_cache_map(997), // FIXME: Change 141 to the next higher prime after max_number_of_entries. 141 works for 128.
	  m_root(LRUCacheListNode::NO_CACHE_LIST_INDEX),
	  m_tail(LRUCacheListNode::NO_CACHE_LIST_INDEX),
	  m_max_number_of_entries(max_number_of_entries),
	  m_number_of_entries(0),
	  m_pParent(pParent)
{
}

LRUCache::~LRUCache()
{
}

void LRUCache::clear()
{
	m_cache_list.clear();
	m_cache_map.clear();
	m_cache_list = std::vector<LRUCacheListNode>(m_max_number_of_entries, LRUCacheListNode());
	m_root = LRUCacheListNode::NO_CACHE_LIST_INDEX;
	m_tail = LRUCacheListNode::NO_CACHE_LIST_INDEX;
	m_number_of_entries = 0;
}


Page *LRUCache::loadNewPageIntoNonFullCache(int new_page_number, void *pData, FILE *fin)
{
	ASSERT_THROW(m_max_number_of_entries > m_number_of_entries,
		     "LRUCache already filled when loading new page.");
	int old_tail;
	if (m_tail == LRUCacheListNode::NO_CACHE_LIST_INDEX) {
		m_root = m_tail = 0;
		old_tail = LRUCacheListNode::NO_CACHE_LIST_INDEX;
		ASSERT_THROW(m_number_of_entries == 0,
			     "Logic error: m_cache_list not empty.");
		++m_number_of_entries;
	} else {
		old_tail = m_tail;
		int new_tail = m_number_of_entries;
		m_cache_list[m_tail].m_next_index = new_tail;
		m_tail = new_tail;
		m_cache_list[new_tail].m_prev_index = old_tail;
		m_cache_list[new_tail].m_next_index = LRUCacheListNode::NO_CACHE_LIST_INDEX;
		++m_number_of_entries;
	}

	Page newPage;
	m_pParent->loadPage(new_page_number, pData, newPage);
	m_cache_list[m_tail] = LRUCacheListNode(new_page_number, 
						newPage,
						LRUCacheListNode::NO_CACHE_LIST_INDEX, // next_index
						old_tail); // prev_index

	m_cache_map.insert(std::make_pair(new_page_number, m_tail));

	return &(m_cache_list[m_tail].m_page);
}


Page *LRUCache::evictBackAndLoadNewPage(int new_page_number, FILE *fin)
{
	ASSERT_THROW(m_max_number_of_entries == m_number_of_entries,
		     "LRUCache not filled before evict.");
	int old_tail = m_tail;
	LRUCacheListNode back = m_cache_list[old_tail];
	m_tail = back.m_prev_index;
	m_cache_list[m_tail].m_next_index = LRUCacheListNode::NO_CACHE_LIST_INDEX;
	
	m_cache_map.erase(back.m_page_number);

	// Reuse old page
	void *pNewPageData = back.m_page.getData();

	Page newPage;
	m_pParent->loadPage(new_page_number, pNewPageData, newPage);


	int new_root = old_tail;

	m_cache_list[new_root] = LRUCacheListNode(new_page_number, newPage,
						  m_root,    // next
						  LRUCacheListNode::NO_CACHE_LIST_INDEX); // prev

	m_cache_list[m_root].m_prev_index = new_root;

	m_root = new_root;

	m_cache_map.insert(std::make_pair(new_page_number, new_root));

	return &(m_cache_list[new_root].m_page);
}

Page *LRUCache::findPageInCache(int page_number) // Returns nil on not found
{
	int list_index = LRUCacheListNode::NO_CACHE_LIST_INDEX;
	m_cache_map.find(page_number, &list_index);
	if (list_index == LRUCacheListNode::NO_CACHE_LIST_INDEX) {
		return 0; // Not found
	} else {
		// Found
		return &(m_cache_list[list_index].m_page);
	}
}








