	long m_schema_string_index;
	typedef std::map<id_d_t, std::string> ID_D2STRING_map_t;
	ID_D2STRING_map_t m_otid2otn;
	ID_D2STRING_map_t m_enumid2enumname;
	typedef std::map<std::string, id_d_t> STRING2ID_D_map_t;
	STRING2ID_D_map_t m_otn2otid;
	STRING2ID_D_map_t m_enumname2enumid;
	typedef std::map<std::string, BPTTable*> OTN2BPTTable_map_t;
	OTN2BPTTable_map_t m_table_map;
	OTN2BPTTable_map_t m_index_map;
	/*
	typedef std::map<long, std::string> OFFSET2STRING_map_t;
	OFFSET2STRING_map_t m_offset2string_cache;
	typedef std::map<std::string, long> STRING2OFFSET_map_t;
	STRING2OFFSET_map_t m_string2offset_cache;
	*/
	typedef std::map<long, std::string> OFFSET2STRING_map_t;
	OFFSET2STRING_map_t m_offset2string_cache;
	typedef std::set<std::string> OTNFN_set_t;
	OTNFN_set_t m_string_set_cache_filled;
 public:
	// Constructor and destructor
	BPTEMdFConnection();
	virtual ~BPTEMdFConnection();

	// Tells us if we are row-based. False mans column-based
	bool isRowBased() const;
	bool isColumnBased() const;
	bool hasMonadSetLengthColumn() const;

	std::string getIndexTableName(const std::string& indexed_otn, const std::string& indexed_feature) const;
	std::list<std::string> getIndexColumnNames(bool bIsFirstMonadOfSetOfMonads) const;

	int getLastPageNumberInDB(void) const;
	size_t getPayloadOffset(void) const;
	bool saveThisDBAsPayload(const std::string& new_database_name);
	bool dumpPayload(const std::string& new_database_name, const std::string& new_key);
	bool hasPayload(bool& bHasPayload);

	// Encrypt current connection into file with name new_database_name 
	// using new_key as key
	bool encryptWithKey(const std::string& new_database_name, const std::string& new_key);
  
	// Status of connection
	// Returns true on connection good, false on connection bad
	virtual bool connectionOk(void);

	// Executing SELECT
	virtual bool execSelect(const std::string& query);

	// Executing all others.  We are a static database, so we don't ever succeed.
	virtual bool execCommand(const std::string& query) { return false; };

	virtual bool execQuery(const std::string& OTN,
			       eQueryKind query_kind,
			       const SetOfMonads *pSOM, // May be 0
			       const std::string& monad_set_name,
			       const std::list<std::string>& columns_to_get,
			       EMdFFFeatures *pConstraints);

	bool getCursorFeatureIndex(const std::string& feature_name, int& cursor_feature_index);

	// Get last error message
	// Returns true on error message available 
	// (even if it is "OK"), false on error 
	// message not available.
	virtual bool errorMessage(std::string& out);

	// Transactions. Do nothing, and return success by default
	virtual bool beginTransaction(void) { return true; };
	virtual bool commitTransaction(void) { return true; };
	virtual bool abortTransaction(void) { return true; };

	// Field count
	// Returns -1 on no fields.
	virtual int getNoOfFields(void);


	// Getting next tuple
	// Returns true on success, false on failure
	// On success, bMoreTuples tells us whether there are any more tuples.
	virtual bool getNextTuple(bool& bMoreTuples);

	// Is there a row in the local cache?
	// Must be called right after the query is done.
	virtual bool hasRow(void) const;

	// Tuple-access
	// First tuple is 0
	// First field is 0.
	virtual bool accessTuple(int field_no, 
				 bool& result);
	virtual bool accessTuple(int field_no, 
				 long& result);
	virtual bool accessTuple(int field_no, 
				 std::string& result);
	virtual bool accessMonadSetTuple(int field_no, std::string& result);

	// Be done with a result set
	virtual void finalize(void);

	// UseDatabase
	virtual bool useDatabase(const std::string& database_name, const std::string& key);
	virtual bool useDatabase(const std::string& database_name, const std::string& key, bool bIsInitializingOrCreating);

	bool getMax_m(monad_m& /* out */ max_m);
	bool getMin_m(monad_m& /* out */ min_m);
	bool getSchemaVersion(/* out */ long& schema_version);
	bool getLargestObjectLength(const std::string& object_type_name,
				    /* out */ monad_m& largest_object_length);
