	bool findInHashTable(const std::string& instr,
			     long& out_offset);

	bool loadStringSetIntoCacheBPT(const std::string& normalized_object_type_name,
				       const std::string& encoded_feature_name,
				       /* may be 0 */ Table *pTable);
	bool getStringOffset(const std::string& normalized_object_type_name,
			     const std::string& encoded_feature_name,
			     const std::string& instr,
			     long& out_offset);
	bool selectMonadSets(/* out */ std::list<std::string>& monad_set_names);
	bool monadSetExists(const std::string& monad_set_name, 
			    /* out */ bool& bExists,
			    /* out */ SetOfMonads& som);
 private:
	enum {
		HEADER_SIZE = 64,
		STRING_LENGTH_SIZE = 4
	};
	BPTTable *getTableOrIndex(const std::string& index_name_or_otn);
	BPTTable *getTable(const std::string& OTN, bool bReportError);
	BPTTable *getIndex(const std::string& index_table_name, bool bReportError);
	size_t read_bytes_table(unsigned char* pBuffer, long offset, long nBytesToRead);
