bool BPTEMdFConnection::getLargestObjectLengthForSOMFeature(const std::string& object_type_name,
							    const std::string& set_of_monas_feature_name,
							    /* out */ monad_m& largest_object_length)
{
	if (m_pSchema == 0) {
		return false;
	}
	std::string otn = normalizeOTName(object_type_name);

	const JSONValue *pOT = (*m_pSchema)["object_types"];
	if (pOT == 0) {
		return false;
	}
	const JSONValue *pOTN = (*pOT)[otn];
	if (pOTN == 0) {
		return false;
	}
	const JSONValue *pOTN_COLUMNS = (*pOTN)["columns"];
	if (pOTN_COLUMNS == 0) {
		return false;
	}
	if (pOTN_COLUMNS->getKind() != kJSONObject) {
		return false;
	}

	std::string encoded_feature_name = encodeFeatureNameBPT(set_of_monas_feature_name);
	if (!pOTN_COLUMNS->hasObjectKey(encoded_feature_name)) {
		return false;
	}
	const JSONValue *pCOLUMN = (*pOTN_COLUMNS)[encoded_feature_name];

	if (!pCOLUMN->hasObjectKey("set_of_monads_largest_object_length")) {
		return false;
	}
	const JSONValue *pResult = (*pCOLUMN)["set_of_monads_largest_object_length"];
	if (pResult->getKind() != kJSONInteger) {
		return false;
	}

	largest_object_length = pResult->getInteger();

	return true;
}


bool BPTEMdFConnection::getObjectTypes(/* out */ std::list<std::string>& Result)
{
	if (m_pSchema == 0) {
		return false;
	}
	
	Result.clear();
		
	const JSONValue *pOTL = (*m_pSchema)["object_type_list"];
	if (pOTL != 0) {
		if (pOTL->getKind() != kJSONList) {
			return false;
		}
		const std::list<JSONValue*>& object_type_names = pOTL->getList();
		std::list<JSONValue*>::const_iterator ci = object_type_names.begin();
		while (ci != object_type_names.end()) {
			const JSONValue *pOTN = *ci;
			if (pOTN->getKind() != kJSONString) {
				return false;
			}

			std::string otn = pOTN->getString();

			Result.push_back(otn);

			++ci;
		}
	} else {
		const JSONValue *pOT = (*m_pSchema)["object_types"];
		if (pOT == 0) {
			return false;
		}
		if (pOT->getKind() != kJSONObject) {
			return false;
		}
		std::multimap<long, std::string> otmap;
		std::list<std::string> ot_names = pOT->getObjectKeys();
		std::list<std::string>::const_iterator ci = ot_names.begin();
		while (ci != ot_names.end()) {
			std::string otn = *ci;
			
			const JSONValue *pOTN = (*(*m_pSchema)["object_types"])[otn];
			
			if (pOTN == 0) {
				appendError("Could not get object_types entry for object type '" + otn + "'.");
				return false;
			}
			
			if (pOTN->getKind() != kJSONObject) {
				return false;
			}
			
			const JSONValue *pSTARTING_INDEX = (*pOTN)["starting_index"];
			if (pSTARTING_INDEX == 0
			    || pSTARTING_INDEX->getKind() != kJSONInteger) {
				return false;
			}
			
			long starting_index = pSTARTING_INDEX->getInteger() + BPTEMdFConnection::HEADER_SIZE;
			
			otmap.insert(std::make_pair(starting_index, otn));
			
			// std::cerr << "UP234: Inserting object type '" << otn << "' with starting_index: " << starting_index << std::endl;
			
			++ci;
		}
		
		std::multimap<long, std::string>::const_iterator ci2 = otmap.begin();
		while (ci2 != otmap.end()) {
			Result.push_back(ci2->second);
			// std::cerr << "UP236: Pushing otn: " << ci2->second << std::endl;
			++ci2;
		}
		
	}
	return true;
}


bool BPTEMdFConnection::getFeaturesForObjectType(id_d_t object_type_id,
						 /* out */ std::list<FeatureInfo>& Result)
	
{
	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pOT = (*m_pSchema)["object_types"];
	if (pOT == 0) {
		return false;
	}
	if (pOT->getKind() != kJSONObject) {
		return false;
	}

	bool bExists;
	std::string object_type_name;
	eObjectRangeType dummy_objectRangeType;
	eMonadUniquenessType dummy_monadUniquenessType;
	if (!objectTypeExists(object_type_id,
			      bExists,
			      object_type_name,
			      dummy_objectRangeType,
			      dummy_monadUniquenessType)) {
		return false;
	}

	if (!bExists) {
		return false;
	}
	

	const JSONValue *pOTN = (*pOT)[object_type_name];
	if (pOTN == 0) {
		return false;
	}
	if (pOTN->getKind() != kJSONObject) {
		return false;
	}

	if (pOTN->hasObjectKey("features")) {
		const JSONValue *pOTN_FEATURES = (*pOTN)["features"];
		if (pOTN_FEATURES == 0) {
			return false;
		}
		if (pOTN_FEATURES->getKind() != kJSONList) {
			return false;
		}

		const JSONValue *pOTN_COLUMNS = (*pOTN)["columns"];
		if (pOTN_COLUMNS == 0) {
			return false;
		}
		if (pOTN_COLUMNS->getKind() != kJSONObject) {
			return false;
		}
		
		const std::list<JSONValue*>& feature_names = pOTN_FEATURES->getList();
		std::list<JSONValue*>::const_iterator ci = feature_names.begin();
		while (ci != feature_names.end()) {
			const JSONValue *pFeatureName = *ci;
			if (pFeatureName == 0) {
				return false;
			}
			if (pFeatureName->getKind() != kJSONString) {
				return false;
			}
			
			std::string feature_name = pFeatureName->getString();
			
			std::string column_name;
			if (feature_name == "self") {
				column_name = "object_id_d";
			} else {
				column_name = "mdf_" + feature_name;
			}

			const JSONValue *pFeature = (*pOTN_COLUMNS)[column_name];
			if (pFeature == 0) {
				return false;
			}
			if (pFeature->getKind() != kJSONObject) {
				return false;
			}
			
			const JSONValue *pType = (*pFeature)["type"];
			if (pType == 0) {
				return false;
			}
			if (pType->getKind() != kJSONString) {
				return false;
			}
			
			std::string type_name = pType->getString();
			id_d_t feature_type;
			if (!getFeatureTypeIdFromTypeName(type_name, feature_type)) {
				return false;
			}
			
			// Fake a default value or take a real default value
			std::string default_value;
			const JSONValue *pDefaultValue = (*pFeature)["default_value"];
			if (pDefaultValue != 0) {
				if (pDefaultValue->getKind() != kJSONString) {
					return false;
				}
				
				default_value = pDefaultValue->getString();
			} else {
				
				if (featureTypeIdIsASCIIorSTRING(feature_type)) {
					default_value = "";
				} else if (featureTypeIdIsListOf(feature_type)) {
					default_value = "";
				} else if (featureTypeIdIsSOM(feature_type)) {
					default_value = " { } ";
				} else {
					default_value = "0";
				}
			}

			bool bIsComputed;
			if (feature_name == "self") {
				bIsComputed = true;
			} else {
				bIsComputed = false;
			}

			FeatureInfo info(feature_name,
					 feature_type,
					 default_value,
					 bIsComputed);
			Result.push_back(info);
			
			++ci;
		}
	} else {
		const JSONValue *pOTN_COLUMNS = (*pOTN)["columns"];
		if (pOTN_COLUMNS == 0) {
			return false;
		}
		if (pOTN_COLUMNS->getKind() != kJSONObject) {
			return false;
		}
		
		std::list<std::string> column_names = pOTN_COLUMNS->getObjectKeys();
		std::list<std::string>::const_iterator ci = column_names.begin();
		while (ci != column_names.end()) {
			std::string column_name = *ci;
			std::string feature_name;
			if (column_name == "object_id_d") {
				feature_name = "self";
				FeatureInfo info("self",
						 FEATURE_TYPE_ID_D,
						 "0",
						 true);
				Result.push_back(info);
				
			} else if (column_name.substr(0, 4) == "mdf_") {
				feature_name = column_name.substr(4, std::string::npos);
				
				const JSONValue *pFeature = (*pOTN_COLUMNS)[column_name];
				if (pFeature == 0) {
					return false;
				}
				if (pFeature->getKind() != kJSONObject) {
					return false;
				}
				
				const JSONValue *pType = (*pFeature)["type"];
				if (pType == 0) {
					return false;
				}
				if (pType->getKind() != kJSONString) {
					return false;
				}
				
				std::string type_name = pType->getString();
				id_d_t feature_type;
				if (!getFeatureTypeIdFromTypeName(type_name, feature_type)) {
					return false;
				}
				
				// Fake a default value or take a real default value
				std::string default_value;
				const JSONValue *pDefaultValue = (*pFeature)["default_value"];
				if (pDefaultValue != 0) {
					if (pDefaultValue->getKind() != kJSONString) {
						return false;
					}
					
					default_value = pDefaultValue->getString();
				} else {
					
					if (featureTypeIdIsASCIIorSTRING(feature_type)) {
						default_value = "";
					} else if (featureTypeIdIsListOf(feature_type)) {
						default_value = "";
					} else if (featureTypeIdIsSOM(feature_type)) {
						default_value = " { } ";
					} else {
						default_value = "0";
					}
				}
				
				FeatureInfo info(feature_name,
						 feature_type,
						 default_value,
						 false);
				Result.push_back(info);
			}
			++ci;
		}
	}
	
	return true;
}

bool BPTEMdFConnection::getFeatureTypeIdFromTypeName(const std::string& type_name, id_d_t& /* out */ feature_type)
{
	feature_type = 0;
	if (type_name == "integer") {
		feature_type = FEATURE_TYPE_INTEGER;
	} else if (type_name == "string") {
		feature_type = FEATURE_TYPE_STRING;
	} else if (type_name == "ascii") {
		feature_type = FEATURE_TYPE_ASCII;
	} else if (type_name == "id_d") {
		feature_type = FEATURE_TYPE_ID_D;
	} else if (type_name == "set of monads") {
		feature_type = FEATURE_TYPE_SET_OF_MONADS;
	} else if (type_name.substr(0, 4) == "list") {
		if (type_name == "list of id_d") {
			feature_type = FEATURE_TYPE_LIST_OF_ID_D;
		} else if (type_name == "list of integer") {
			feature_type = FEATURE_TYPE_LIST_OF_INTEGER;
		} else {
			std::string enum_name = type_name.substr(8, std::string::npos);
			bool bEnumExists;
			id_d_t enum_id;
			if (!enumExists(enum_name,
					bEnumExists,
					enum_id)) {
				return false;
			}
			feature_type = STRIP_ENUM_ID_OF_LOWER_BITS(enum_id)
				| FEATURE_TYPE_LIST_OF_ENUM;
		}
	} else {
		// is enum
		std::string enum_name = type_name;
		bool bEnumExists;
		id_d_t enum_id;
		if (!enumExists(enum_name,
				bEnumExists,
				enum_id)) {
			return false;
		}
		if (!bEnumExists) {
			return false;
		}
		feature_type = STRIP_ENUM_ID_OF_LOWER_BITS(enum_id) | FEATURE_TYPE_ENUM;
	}
	return true;
}

bool BPTEMdFConnection::objectTypeExists(id_d_t object_type_id,
					 /* out */ bool& result, 
					 /* out */ std::string& object_type_name,
					 /* out */ eObjectRangeType& objectRangeType,
					 /* out */ eMonadUniquenessType& monadUniquenessType)
{
	ID_D2STRING_map_t::const_iterator ci = m_otid2otn.find(object_type_id);
	if (ci == m_otid2otn.end()) {
		result = false;
		return true;
	} else {
		object_type_name = ci->second;
		return objectTypeExists(object_type_name,
					result,
					object_type_id,
					objectRangeType,
					monadUniquenessType);
	}
	return true;
}

bool BPTEMdFConnection::indexExists(const std::string& index_table_name,
				    /* out */ bool& result)
{
	// Assume it doesn't exist
	result = false;

	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pIndexes = (*m_pSchema)["indexes"];
	if (pIndexes == 0) {
		return false;
	}
	if (pIndexes->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pOTN = (*pIndexes)[index_table_name];
	if (pOTN == 0) {
		result = false;
		return true;
	}
	if (pOTN->getKind() != kJSONObject) {
		return false;
	}
	result = true;
	return true;
}

bool BPTEMdFConnection::indexExists(const std::string& indexed_otn,
				    const std::string& indexed_feature,
				    /* out */ bool& result)
{
	std::string index_table_name = getIndexTableName(indexed_otn, indexed_feature);
	return indexExists(index_table_name, result);
}


bool BPTEMdFConnection::objectTypeExists(const std::string& object_type_name, 
					 /* out */ bool& result, 
					 /* out */ id_d_t& object_type_id,
					 /* out */ eObjectRangeType& objectRangeType,
					 /* out */ eMonadUniquenessType& monadUniquenessType)
{
	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pOT = (*m_pSchema)["object_types"];
	if (pOT == 0) {
		return false;
	}
	if (pOT->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pOTN = (*pOT)[object_type_name];
	if (pOTN == 0) {
		result = false;
		return true;
	}
	if (pOTN->getKind() != kJSONObject) {
		return false;
	}
	STRING2ID_D_map_t::const_iterator ci = m_otn2otid.find(object_type_name);
	if (ci == m_otn2otid.end()) {
		result = false;
		return true;
	} else {
		object_type_id = ci->second;
	}

	const JSONValue *pRangeType = (*pOTN)["range_type"];
	if (pRangeType == 0) {
		return false;
	}
	if (pRangeType->getKind() != kJSONInteger) {
		return false;
	}
	int range_type = pRangeType->getInteger();
	switch (range_type) {
	case 0:
		objectRangeType = kORTSingleMonad;		
		break;
	case 1:
		objectRangeType = kORTSingleRange;		
		break;
	case 2:
		objectRangeType = kORTMultipleRange;		
		break;
	default:
		return false;
	}

	const JSONValue *pUniquenessfirstmonad = (*pOTN)["uniqueness_firstmonad"];
	if (pUniquenessfirstmonad == 0) {
		return false;
	}
	if (pUniquenessfirstmonad->getKind() != kJSONInteger) {
		return false;
	}
	int uniqueness_firstmonad = pUniquenessfirstmonad->getInteger();
	switch (uniqueness_firstmonad) {
	case 0:
		monadUniquenessType = kMUTUniqueFirstMonads;
		break;
	case 1:
		monadUniquenessType = kMUTNonUniqueMonads;
		break;
	default:
		return false;
	}

	result = true; // It exists if we got this far
	return true;
}


bool BPTEMdFConnection::getEnumerations(/* out */ std::list<std::string>& Result)
{
	if (m_pSchema == 0) {
		return false;
	}

	Result.clear();

	const JSONValue *pEL = (*m_pSchema)["enum_list"];
	if (pEL != 0) {
		if (pEL->getKind() != kJSONList) {
			return false;
		}
		const std::list<JSONValue*>& jsonvalue_list = pEL->getList();
		std::list<JSONValue*>::const_iterator ci = jsonvalue_list.begin();
		while (ci != jsonvalue_list.end()) {
			const JSONValue *pEnumName = *ci;

			std::string enum_name = pEnumName->getString();

			Result.push_back(enum_name);

			++ci;
		}
	} else {
		const JSONValue *pOT = (*m_pSchema)["enums"];
		if (pOT == 0) {
			return false;
		}
		if (pOT->getKind() != kJSONObject) {
			return false;
		}
		Result = pOT->getObjectKeys();
	}
	return true;
}


bool BPTEMdFConnection::enumExists(id_d_t enum_id,
				   /* out */ bool& result,
				   /* out */ std::string& enum_name)
{
	ID_D2STRING_map_t::const_iterator ci = m_enumid2enumname.find(enum_id);
	if (ci == m_enumid2enumname.end()) {
		result = false;
		return true;
	} else {
		enum_name = ci->second;
		id_d_t dummy_enum_id;
		return enumExists(enum_name,
				  result,
				  dummy_enum_id);
	}
	return true;
}


bool BPTEMdFConnection::enumExists(const std::string& enum_name, 
		/* out */ bool& result,
		/* out */ id_d_t& enum_id)
{
	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pEnums = (*m_pSchema)["enums"];
	if (pEnums == 0) {
		return false;
	}
	if (pEnums->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pEnum = (*pEnums)[enum_name];
	if (pEnum == 0) {
		result = false;
		return true;
	}
	if (pEnum->getKind() != kJSONObject) {
		return false;
	}
	STRING2ID_D_map_t::const_iterator ci = m_enumname2enumid.find(enum_name);
	if (ci == m_enumname2enumid.end()) {
		result = false;
		return true;
	} else {
		enum_id = ci->second;
	}
	// std::cerr << "UP416: enum_name = " << enum_name << ", enum_id = " << enum_id << std::endl;
	result = true;
	return true;
}


bool BPTEMdFConnection::enumConstExists(const std::string& enum_const_name, 
					id_d_t enum_id,
					/* out */ bool& result,
					/* out */ long& value,
					/* out */ bool& is_default)
{
	std::string enum_name;
	bool bEnumExists;
	enum_id = STRIP_ENUM_ID_OF_LOWER_BITS(enum_id);
	if (!enumExists(enum_id,
			bEnumExists,
			enum_name)) {
		return false;
	}
	if (!bEnumExists) {
		// This is so as to be compliant with the EMdFDB
		// implementation, which simply sets bExists to false
		// and returns true if there are no rows in the query
		// result set. This also occurs if the enum_id does
		// not exist at all.
		result = false;
		return true;
	}
	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pEnums = (*m_pSchema)["enums"];
	if (pEnums == 0) {
		return false;
	}
	if (pEnums->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pEnum = (*pEnums)[enum_name];
	if (pEnum == 0) {
		result = false;
		return true;
	}
	if (pEnum->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pEnumConst = (*pEnum)[enum_const_name];
	if (pEnumConst == 0) {
		result = false;
		return true;
	}
	if (pEnumConst->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pEnumConstRealValue = (*pEnumConst)["real_value"];
	if (pEnumConstRealValue == 0) {
		result = false;
		return true;
	}
	if (pEnumConstRealValue->getKind() != kJSONInteger) {
		return false;
	}
	
	value = pEnumConstRealValue->getInteger();

	const JSONValue *pEnumConstIsDefault = (*pEnumConst)["is_default"];
	if (pEnumConstIsDefault == 0) {
		result = false;
		return true;
	}
	if (pEnumConstIsDefault->getKind() != kJSONBoolean) {
		return false;
	}
	
	is_default = pEnumConstIsDefault->getBoolean();

	result = true;
	return true;
}


bool BPTEMdFConnection::enumConstExists(long value,
					id_d_t enum_id,
					bool& bExists,
					/* out */ std::string& enum_const_name,
					/* out */ bool& is_default)
{
	std::string enum_name;
	bool bEnumExists;
	if (!enumExists(enum_id,
			bEnumExists,
			enum_name)) {
		return false;
	}
	if (!bEnumExists) {
		// This is so as to be compliant with the EMdFDB
		// implementation, which simply sets bExists to false
		// and returns true if there are no rows in the query
		// result set. This also occurs if the enum_id does
		// not exist at all.
		bExists = false;
		return true;
	}
	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pEnums = (*m_pSchema)["enums"];
	if (pEnums == 0) {
		return false;
	}
	if (pEnums->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pEnum = (*pEnums)[enum_name];
	if (pEnum == 0) {
		bExists = false;
		return true;
	}
	if (pEnum->getKind() != kJSONObject) {
		return false;
	}
	std::list<std::string> enum_const_names = pEnum->getObjectKeys();
	std::list<std::string>::const_iterator ci = enum_const_names.begin();
	while (ci != enum_const_names.end()) {
		std::string ec_name = *ci;
		const JSONValue *pEnumConst = (*pEnum)[ec_name];
		if (pEnumConst == 0) {
			return false;
		}
		if (pEnumConst->getKind() != kJSONObject) {
			return false;
		}
		const JSONValue *pEnumConstRealValue = (*pEnumConst)["real_value"];
		if (pEnumConstRealValue == 0) {
			return false;
		}
		if (pEnumConstRealValue->getKind() != kJSONInteger) {
			return false;
		}
		long ec_value = pEnumConstRealValue->getInteger();
		if (ec_value == value) {
			enum_const_name = ec_name;
			bExists = true;
			return true;
		}
		
		++ci;
	}
	bExists = false;
	return true;
}


bool BPTEMdFConnection::getEnumConstants(const std::string& enum_name,
					 /* out */ std::list<EnumConstInfo>& Result)
{
	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pEnums = (*m_pSchema)["enums"];
	if (pEnums == 0) {
		return false;
	}
	if (pEnums->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pEnum = (*pEnums)[enum_name];
	if (pEnum == 0) {
		return true;
	}
	if (pEnum->getKind() != kJSONObject) {
		return false;
	}
	std::list<std::string> enum_const_names = pEnum->getObjectKeys();
	std::list<std::string>::const_iterator ci = enum_const_names.begin();
	while (ci != enum_const_names.end()) {
		std::string ec_name = *ci;
		const JSONValue *pEnumConst = (*pEnum)[ec_name];
		if (pEnumConst == 0) {
			return false;
		}
		if (pEnumConst->getKind() != kJSONObject) {
			return false;
		}
		const JSONValue *pEnumConstRealValue = (*pEnumConst)["real_value"];
		if (pEnumConstRealValue == 0) {
			return false;
		}
		if (pEnumConstRealValue->getKind() != kJSONInteger) {
			return false;
		}
		long ec_value = pEnumConstRealValue->getInteger();
		const JSONValue *pEnumConstIsDefault = (*pEnumConst)["is_default"];
		if (pEnumConstIsDefault == 0) {
			return false;
		}
		if (pEnumConstIsDefault->getKind() != kJSONBoolean) {
			return false;
		}
	
		bool bIsDefault = pEnumConstIsDefault->getBoolean();

		EnumConstInfo ecinfo(ec_name, 
				     ec_value, 
				     bIsDefault);
		Result.push_back(ecinfo);
		
		++ci;
	}
	return true;
}


bool BPTEMdFConnection::getEnumConstNameFromValue(long value,
						  const std::string& enum_name,
						  id_d_t enum_id,	
						  bool& bExists,
						  /* out */ std::string& enum_const_name)
{
	if (m_pSchema == 0) {
		return false;
	}

	enum_id = STRIP_ENUM_ID_OF_LOWER_BITS(enum_id);

	const EnumConstInfo *pECI = m_enum_const_cache.find(enum_id, value);
	if (pECI == 0) {
		bExists = false;
		return true;
	}
	enum_const_name = pECI->getName();
	bExists = true;
	return true;
}


bool BPTEMdFConnection::featureExists(const std::string& feature_name,
				      id_d_t object_type_id,
				      /* out */ bool& result,
				      /* out */ id_d_t& feature_type_id,
				      /* out */ std::string& default_value,
				      /* out */ bool& is_computed)
{
	if (m_pSchema == 0) {
		return false;
	}
	const JSONValue *pOT = (*m_pSchema)["object_types"];
	if (pOT == 0) {
		return false;
	}
	if (pOT->getKind() != kJSONObject) {
		return false;
	}

	bool bExists;
	std::string object_type_name;
	eObjectRangeType dummy_objectRangeType;
	eMonadUniquenessType dummy_monadUniquenessType;
	if (!objectTypeExists(object_type_id,
			      bExists,
			      object_type_name,
			      dummy_objectRangeType,
			      dummy_monadUniquenessType)) {
		return false;
	}
	

	const JSONValue *pOTN = (*pOT)[object_type_name];
	if (pOTN == 0) {
		return false;
	}
	if (pOTN->getKind() != kJSONObject) {
		return false;
	}
	const JSONValue *pOTN_COLUMNS = (*pOTN)["columns"];
	if (pOTN_COLUMNS == 0) {
		return false;
	}
	if (pOTN_COLUMNS->getKind() != kJSONObject) {
		return false;
	}

	std::string column_name;
	if (feature_name == "self") {
		feature_type_id = FEATURE_TYPE_ID_D;
		default_value = "0";
		result = true;
		is_computed = true;
		return true;
	} else if (feature_name == "monads") {
		feature_type_id = FEATURE_TYPE_SET_OF_MONADS;
		default_value = " {1} ";
		result = true;
		is_computed = false;
		return true;
	} else {
		std::string lowercase_featurename;
		str_tolower(feature_name, lowercase_featurename);
		column_name = "mdf_" + lowercase_featurename;
		is_computed = false;
	}
	const JSONValue *pFeature = (*pOTN_COLUMNS)[column_name];
	if (pFeature == 0) {
		result = false;
		return true;
	}
	if (pFeature->getKind() != kJSONObject) {
		return false;
	}

	const JSONValue *pType = (*pFeature)["type"];
	if (pType == 0) {
		return false;
	}
	if (pType->getKind() != kJSONString) {
		return false;
	}
	
	std::string type_name = pType->getString();
	if (!getFeatureTypeIdFromTypeName(type_name, feature_type_id)) {
		return false;
	}


	// Fake a default value or take a real default value
	const JSONValue *pDefaultValue = (*pFeature)["default_value"];
	if (pDefaultValue != 0) {
		if (pDefaultValue->getKind() != kJSONString) {
			return false;
		}
		
		default_value = pDefaultValue->getString();
	} else {
		
		if (featureTypeIdIsASCIIorSTRING(feature_type_id)) {
			default_value = "";
		} else if (featureTypeIdIsListOf(feature_type_id)) {
			default_value = "";
		} else if (featureTypeIdIsSOM(feature_type_id)) {
			default_value = " { } ";
		} else {
			default_value = "0";
		}
	}

	result = true;
	return true;
}





bool BPTEMdFConnection::getStringOffset(const std::string& normalized_object_type_name,
					const std::string& encoded_feature_name,
					const std::string& instr,
					long& out_offset)
{

	/*
	STRING2OFFSET_map_t::const_iterator ci = m_string2offset_cache.find(instr);
	if (ci != m_string2offset_cache.end()) {
		out_offset = ci->second;
		return true;
	}
	*/

	if (!findInHashTable(instr, out_offset)) {
		return false;
	}
	return true;
}

bool BPTEMdFConnection::findInHashTable(const std::string& instr,
					long& out_offset)
{
	int hash_entry_index = hash_djb2(instr, m_hashtable_size);
	long hash_offset = m_hashtable_table_offset + hash_entry_index * 4;
	
	unsigned char sBuffer[5];
	if (read_bytes_string(sBuffer, hash_offset, 4) != 4) {
		appendError("Unable to read hash table entry.");
		return false;
	}
	long hash_entry = fourbytes2long(sBuffer);
	if (hash_entry == 0) {
		appendError("Hash table entry was empty.");
		return false;
	} 
	if (hash_entry < m_hashtable_lists_offset) {
		out_offset = hash_entry;
		std::string test_string;
		if (!read_string(out_offset, test_string)) {
			appendError("Unable to read string from hash table.");
			return false;
		}
	
		if (test_string == instr) {
			return true;
		} else {
			appendError("string found in hash table wasn't the string we meant to find. String found: '" + test_string + "'");
			return false;
		}
	} else {
		unsigned long string_index = 0;
		long hash_list_offset = hash_entry;
		if (m_schema_version == 0x01
		    || m_schema_version == 0x02
		    || m_schema_version == 0x05) {
			while (true) {
				if (read_bytes_string(sBuffer, hash_list_offset, 4) != 4) {
					appendError("Unable to read hash table entry.");
					return false;
				}
				string_index = fourbytes2long(sBuffer);
				if (string_index == 0) {
					// The hash list ends with a 0.
					return false;
				}
				std::string test_string;
				if (!read_string(string_index, test_string)) {
					appendError("Unable to read string from has table list.");
					return false;
				}
				
				if (test_string == instr) {
					out_offset = string_index;
					return true;
				}
				
				hash_list_offset += 4;
			}
		} else if (m_schema_version == 0x03
			   || m_schema_version == 0x07) {
			while (true) {
				if (read_bytes_string(sBuffer, hash_list_offset, 5) != 5) {
					appendError("Unable to read hash table entry.");
					return false;
				}
				string_index = 0;
				int nBytesRead = varint2ulong(sBuffer, &string_index);
				if (string_index == 0) {
					// The hash list ends with a 0.
					return false;
				}
				std::string test_string;
				if (!read_string(string_index, test_string)) {
					appendError("Unable to read string from has table list.");
					return false;
				}
				
				if (test_string == instr) {
					out_offset = string_index;
					return true;
				}
				
				hash_list_offset += nBytesRead;
			}

		} else {
			ASSERT_THROW(false,
				     "Unknown schema version in BPT engine: " + long2string(m_schema_version));
		}
	}
}


bool BPTEMdFConnection::loadStringSetIntoCacheBPT(const std::string& normalized_object_type_name,
						  const std::string& encoded_feature_name,
						  Table *pTable /* may be 0 */)
{
	std::string compound_name = normalized_object_type_name + encoded_feature_name;
	if (pTable == 0
	    && m_string_set_cache_filled.find(compound_name) != m_string_set_cache_filled.end()) {
		// We don't need to do it if:
		// (a) We are not to retrieve a Table, and
		// (b) m_string_set_cache_filled has an entry for this
		//     OTN + feature_name combination.
		return true;
	}
	    
	std::list<std::string> columns_to_get;
	columns_to_get.push_back(encoded_feature_name);

	if (!execQuery(normalized_object_type_name,
		       kQueryKindPartOf,
		       0,
		       "monads",
		       columns_to_get,
		       0)) {
		return false;
	}
	bool bMoreTuples = hasRow();
	std::set<std::string> myset;
	while (bMoreTuples) {
		std::string str;
		if (!accessTuple(0, str)) {
			return false;
		}
		myset.insert(str);
		if (!getNextTuple(bMoreTuples)) {
			return false;
		}
	}
	m_string_set_cache_filled.insert(compound_name);

	if (pTable != 0) {
		std::set<std::string>::const_iterator ci = myset.begin();
		std::set<std::string>::const_iterator cend = myset.end();
		while (ci != cend) {
			pTable->startNewRow();
			pTable->append(*ci);
			
			++ci;
		}
	}

	return true;
}


