BPTEMdFConnection::BPTEMdFConnection(const BPTEMdFConnection&)
{
	// Nothing to do: This is private, and we will never call it.
	ASSERT_THROW(false,
		     "BPTEMdFConnection copy-constructor isn't implemented!");
}


BPTEMdFConnection& BPTEMdFConnection::operator=(const BPTEMdFConnection&)
{
	// Nothing to do: This is private, and we will never call it.
	ASSERT_THROW(false,
		     "BPTEMdFConnection::operator= isn't implemented!");
	// Fool the MSVC compiler into thinking that this does return a value
	return *this;
}


bool BPTEMdFConnection::openFile(const std::string& database_name, const std::string& key)
{
		
	// fopen sets m_pPageCache to NULL if not successful
	m_pPageCache = new PageCache(database_name.c_str(), 128, key);
	if (!m_pPageCache->connectionOk()) {
		delete m_pPageCache;
		m_pPageCache = 0;
		return false;
	}

	return true;
}

size_t BPTEMdFConnection::getPayloadOffset(void) const
{
	int last_page_number = getLastPageNumberInDB();
	int first_payload_page_number = last_page_number + 1;
	return first_payload_page_number * Page::PageSize;
}


int BPTEMdFConnection::getLastPageNumberInDB(void) const
{
	// 4 * m_hashtable_size because each entry is 4 bytes long.
	long last_offset = m_hashtable_table_offset + 4 * m_hashtable_size;
	int nLastPage = m_pPageCache->getPageNumber(last_offset);
	return nLastPage;
}

/*
 * The following two methods add code from the file "examples/zpipe.c"
 * in the zlib distribution, version 1.2.7.
 *
 * examples/zpipe.c is in the Public Domain.
 *
 * Code modified by Ulrik Sandborg-Petersen.
 *
 */
#define ZCHUNK_SIZE (8*Page::PageSize)

bool BPTEMdFConnection::saveThisDBAsPayload(const std::string& new_database_name)
{
	if (!connectionOk()) {
		appendError("Connection to original DB not OK.\n");
		return false;
	}

	FILE *pNewFile = BPTfopen(new_database_name.c_str(), "wb");
	if (!pNewFile
	    || ferror(pNewFile) != 0) {
		appendError("Couldn't open file '" + new_database_name + "' for writing.\n");
		return false;
	}

	int ret, flush;
	unsigned have;
	z_stream strm;
	unsigned char in[ZCHUNK_SIZE];
	unsigned char out[ZCHUNK_SIZE];
	int level = 9;
	
	/* allocate deflate state */
	strm.zalloc = Z_NULL;
	strm.zfree = Z_NULL;
	strm.opaque = Z_NULL;
	ret = deflateInit(&strm, level);
	if (ret != Z_OK) {
		// TODO: Interpret ret and add it with appendError()
		appendError("Deflate couldn't init strm. Do we have too little memory?\n");
		fclose(pNewFile);
		return false;
	}

	int nPageNo = 0;
	int i = 0;
	int last_page_in_file = m_pPageCache->getLastPageNumberInFile();
	
	/* compress until end of file */
	do {
		size_t offset = 0;
		bool bBytesReadOK = true;
		strm.avail_in = 0;
		for (i = 0;
		     i < (ZCHUNK_SIZE / Page::PageSize)
			     && bBytesReadOK
			     && nPageNo <= last_page_in_file;) {
			offset = nPageNo * Page::PageSize;
			bBytesReadOK = m_pPageCache->read_bytes(in + i * Page::PageSize, offset, Page::PageSize);
			strm.avail_in += Page::PageSize;

			++i;
			++nPageNo;
		}

		if (!bBytesReadOK) {
			(void)deflateEnd(&strm);
			fclose(pNewFile);
			appendError("Bytes not read properly from input database at offset " + long2string(offset) + "\n");
			return false;
		}

		flush = (nPageNo > last_page_in_file) ? Z_FINISH : Z_NO_FLUSH;
		strm.next_in = in;
		
		/* run deflate() on input until output buffer not full, finish
		   compression if all of source has been read in */
		do {
			strm.avail_out = ZCHUNK_SIZE;
			strm.next_out = out;
			ret = deflate(&strm, flush);    /* no bad return value */
			ASSERT_THROW(ret != Z_STREAM_ERROR,  /* state not clobbered */
				     "ZLib state clobbered.");
			have = ZCHUNK_SIZE - strm.avail_out;
			if (fwrite(out, 1, have, pNewFile) != have || ferror(pNewFile) != 0) {
				(void)deflateEnd(&strm);
				appendError("Error writing to new file.\n");
				fclose(pNewFile);
				return false;
			}
		} while (strm.avail_out == 0);
		ASSERT_THROW(strm.avail_in == 0,     /* all input will be used */
			     "All input was not used by ZLib.");
		
		/* done when last data in file processed */
	} while (flush != Z_FINISH);
	ASSERT_THROW(ret == Z_STREAM_END,        /* stream will be complete */
		     "Zlib stream not complete.");
	
	fclose(pNewFile);
	
	/* clean up and return */
	(void)deflateEnd(&strm);
	return true;
}

bool BPTEMdFConnection::dumpPayload(const std::string& new_database_name, const std::string& new_key)
{
	if (!connectionOk()) {
		appendError("Connection to original DB not OK.\n");
		return false;
	}
	bool bHasPayload;
	if (!hasPayload(bHasPayload)) {
		appendError("Page Cache not initialized.\n");
		return false;
	}
	if (!bHasPayload) {
		appendError("Database doesn't have a payload.\n");
		return false;
	}

	unsigned int codec_key3[4*2];
	bool bUseCodec = false;
	if (!new_key.empty()) {
		if (!decode_codec_key3(new_key.c_str(), new_key.length(), codec_key3)) {
			appendError("Key isn't valid.\n");
			return false;
		}
		bUseCodec = true;
	}

	FILE *pNewFile = BPTfopen(new_database_name.c_str(), "wb");
	if (!pNewFile
	    || ferror(pNewFile) != 0) {
		appendError("Couldn't open file '" + new_database_name + "' for writing.\n");
		return false;
	}

	int ret;
	unsigned have;
	z_stream strm;
	unsigned char in[ZCHUNK_SIZE];
	unsigned char out[ZCHUNK_SIZE];

	/* allocate inflate state */
	strm.zalloc = Z_NULL;
	strm.zfree = Z_NULL;
	strm.opaque = Z_NULL;
	strm.avail_in = 0;
	strm.next_in = Z_NULL;
	ret = inflateInit(&strm);
	if (ret != Z_OK) {
		// TODO: Interpret ret and add it with appendError()
		appendError("Inflate couldn't init strm. Do we have too little memory?\n");
		fclose(pNewFile);
		return false;
	}

	size_t offset = getPayloadOffset();
	int this_file_page_number = getLastPageNumberInDB() + 1;
	int last_page_in_file = m_pPageCache->getLastPageNumberInFile();
	if (this_file_page_number > last_page_in_file) {
		appendError("Database file doesn't have a payload.\n");
		fclose(pNewFile);
		return false;
	}
	int i = 0;

	unsigned char pBuffer[Page::PageSize];
	int offset_into_buffer = 0;
	int new_file_page_no = 0;
	size_t out_offset = 0;

	/* decompress until deflate stream ends or end of file */
	do {
		bool bBytesReadOK = true;
		strm.avail_in = 0;
		for (i = 0;
		     i < (ZCHUNK_SIZE / Page::PageSize)
			     && bBytesReadOK
			     && this_file_page_number <= last_page_in_file;) {
			size_t offset = this_file_page_number * Page::PageSize;
			void *pBuf = &(in[0]) + (i * Page::PageSize);
			bBytesReadOK = m_pPageCache->read_bytes(pBuf, offset, Page::PageSize);
			strm.avail_in += Page::PageSize;

			++i;
			++this_file_page_number;
		}


		if (!bBytesReadOK) {
			(void)inflateEnd(&strm);
			fclose(pNewFile);
			appendError("Bytes not read properly from input database at offset " + long2string(offset) + "\n");
			return false;
		}
		if (strm.avail_in == 0) {
			break;
		}
		strm.next_in = in;
		
		/* run inflate() on input until output buffer not full */
		do {
			strm.avail_out = ZCHUNK_SIZE;
			strm.next_out = out;
			ret = inflate(&strm, Z_NO_FLUSH);
			ASSERT_THROW(ret != Z_STREAM_ERROR,  /* state not clobbered */
				     "inflate returned Z_STREAM_ERROR.");
			switch (ret) {
			case Z_NEED_DICT:
				ret = Z_DATA_ERROR;     /* and fall through */
			case Z_DATA_ERROR:
			case Z_MEM_ERROR:
				(void)inflateEnd(&strm);
				fclose(pNewFile);
				appendError("ZLib returned an error doing inflate.\n");
				return false;
			case Z_STREAM_END:
				;
			}
			have = ZCHUNK_SIZE - strm.avail_out;
			out_offset = 0;
			while (have > 0) {
				// Copy enough bytes into page_buffer
				unsigned int bytes_available_in_buffer = (Page::PageSize - offset_into_buffer);
				int bytes_to_copy = (have <= bytes_available_in_buffer) ? have : bytes_available_in_buffer;

				memcpy(((unsigned char*)pBuffer) + offset_into_buffer, (const void*) (out + out_offset), bytes_to_copy);

				have -= bytes_to_copy;
				out_offset += bytes_to_copy;
				offset_into_buffer += bytes_to_copy;
				ASSERT_THROW(offset_into_buffer <= Page::PageSize,
					     "offset_into_buffer > Page::PageSize");
				if (offset_into_buffer == Page::PageSize) {
					// If page_buffer full, write
					// page with codec, and set
					// offset_into_buffer to 0.
					if (bUseCodec) {
						(void)useCodecOnPageData((void*) pBuffer, new_file_page_no, codec_key3);
					}
					++new_file_page_no;

					if (fwrite(pBuffer, Page::PageSize, 1, pNewFile) != 1
					    || ferror(pNewFile)) {
						(void)inflateEnd(&strm);
						
						fclose(pNewFile);

						appendError("Error writing to output file.\n");

						return false;
					}

					offset_into_buffer = 0;
				}
			}
		} while (strm.avail_out == 0);
		
		/* done when inflate() says it's done */
	} while (ret != Z_STREAM_END);

	/* clean up and return */
	(void)inflateEnd(&strm);
	bool bSuccess = (ret == Z_STREAM_END) ? true : false;
	if (!bSuccess) {
		appendError("ZLib didn't end with Z_STREAM_END, but with: " + long2string(ret) + "\n");
	}
	fclose(pNewFile);
	return bSuccess;
}

bool BPTEMdFConnection::hasPayload(bool& bHasPayload)
{
	if (m_pPageCache == 0) {
		return false;
	}
	bHasPayload = getLastPageNumberInDB() < m_pPageCache->getLastPageNumberInFile();
	return true;
}


bool BPTEMdFConnection::encryptWithKey(const std::string& new_database_name, const std::string& new_key)
{
	if (!connectionOk()) {
		appendError("Connection to original DB not OK.\n");
		return false;
	}

	unsigned int codec_key3[4*2];
	if (!decode_codec_key3(new_key.c_str(), new_key.length(), codec_key3)) {
		appendError("Key isn't valid.\n");
		return false;
	}

	FILE *pNewFile = BPTfopen(new_database_name.c_str(), "wb");
	if (!pNewFile
	    || ferror(pNewFile) != 0) {
		appendError("Couldn't open file '" + new_database_name + "' for writing.\n");
		return false;
	}

	unsigned char pBuffer[Page::PageSize];
	int last_page_number = m_pPageCache->getLastPageNumberInFile();
	for (int pageNo = 0;
	     pageNo <= last_page_number;
	     ++pageNo) {
		long offset = pageNo * Page::PageSize;

		if (m_pPageCache->read_bytes(pBuffer, offset, Page::PageSize)) {
			useCodecOnPageData(pBuffer, pageNo, codec_key3);
			fwrite(pBuffer, Page::PageSize, 1, pNewFile);
		}
	}

	fclose(pNewFile);
	return true;
}



// Returns the number of bytes read
size_t BPTEMdFConnection::read_bytes_table(unsigned char* pBuffer, long offset, long nBytesToRead)
{
	// std::cerr << "UP490: offset= " << offset << " nBytesToRead= " << nBytesToRead << '\n';
	if (m_pPageCache 
	    && m_pPageCache->read_bytes(pBuffer, offset, nBytesToRead)) {
		return nBytesToRead;
	} else {
		return 0;
	}
}

size_t BPTEMdFConnection::read_bytes_string(unsigned char* pBuffer, long offset, long nBytesToRead)
{
	if (m_pPageCache  
	    && m_pPageCache->read_bytes(pBuffer, offset, nBytesToRead)) {
		return nBytesToRead;
	} else {
		return 0;
	}
}

bool BPTEMdFConnection::readMetadata(void)
{
	if (m_pPageCache == 0) {
		return false;
	}

	// Read header
	unsigned char sHeader[HEADER_SIZE];
	read_bytes_table(sHeader, 0L, HEADER_SIZE);

	if (!(headerStartsWithMagic(sHeader))) {
		appendError("File is not a BPT Emdros file.");
		return false;
	}

	m_schema_version = fourbytes2long((void*) &sHeader[4]);
	if (m_schema_version == 0x0000001 ) {
		; // OK
	} else if (m_schema_version == 0x00000002) {
		// Same as 0x01, but with monad set features
		; // OK
	} else if (m_schema_version == 0x00000003) {
		// With columns instead of rows
		; // OK
	} else if (m_schema_version == 0x00000005) {
		// With rows
		; // OK
	} else if (m_schema_version == 0x00000007) {
		// With columns instead of rows
		; // OK
	} else {
		appendError("Unknown schema version " + long2string(m_schema_version) + " for BPT Emdros file.");
		return false;
	}

	m_total_table_size = fourbytes2long((void*) &sHeader[8]);
	m_strings_start = m_total_table_size + HEADER_SIZE;

	m_schema_string_index = fourbytes2long((void*) &sHeader[12]);

	m_hashtable_lists_offset = fourbytes2long((void*) &sHeader[16]);
	m_hashtable_table_offset = fourbytes2long((void*) &sHeader[20]);
	m_hashtable_size = fourbytes2long((void*) &sHeader[24]);

	std::string schema;
	if (!read_string(m_schema_string_index, schema)) {
		appendError("Could not read schema while opening DB.");
		return false;
	}

	JSONExecEnv *pJSONEE = new JSONExecEnv();
	bool bResult = false;
	JSONValue *pJSONValue = parseJSON(pJSONEE, schema, bResult);
	if (!bResult) {
		DEBUG_X_FAILED("BPTEMdFConnection::readMetadata", "parsing schema");
		DEBUG_X_IS_WRONG("BPTEMdFConnection::readMetadata",
				 pJSONEE->getError() + "\n");
		appendError("Reading metadata from file:\nSchema did not parse!\nError message follows:\n" + pJSONEE->getError());
		delete pJSONValue;
		delete pJSONEE;
		return false;
	} else {
		// First throw away any existing schema.
		delete m_pSchema;

		// Then set the new schema.
		m_pSchema = pJSONValue;

		delete pJSONEE;
	}

	std::list<std::string> object_type_names;
	const JSONValue *pOT = (*m_pSchema)["object_types"];
	if (pOT == 0) {
		return false;
	}
	if (pOT->getKind() != kJSONObject) {
		return false;
	}

	//object_type_names = pOT->getObjectKeys();
	if (!getObjectTypes(object_type_names)) {
		return false;
	}

	// Generate object_type_ids.
	m_otid2otn.clear();
	m_otn2otid.clear();
	std::list<std::string>::const_iterator ci = object_type_names.begin();
	id_d_t object_type_id = 10000;
	while (ci != object_type_names.end()) {
		std::string otn = *ci;
		m_otid2otn.insert(std::make_pair(object_type_id, otn));
		m_otn2otid.insert(std::make_pair(otn, object_type_id));
		// std::cerr << "UP232: Inserted object type '" << otn << "' with object_type_id = " << object_type_id << std::endl;
		++object_type_id;
		++ci;
	}

	std::list<std::string> enum_names;
	if (!getEnumerations(enum_names)) {
		appendError("Enumerations could not be found while opening DB.");
		return false;
	}

	// Generate enum ids
	m_enumname2enumid.clear();
	m_enumid2enumname.clear();
	m_enum_const_cache.clear();
	ci = enum_names.begin();
	id_d_t enum_counter = 1;
	while (ci != enum_names.end()) {
		std::string enum_name = *ci;
		id_d_t enum_id = enum_counter << SEQUENCE_TYPE_IDS_FREE_LOWER_BITS;
		m_enumid2enumname.insert(std::make_pair(enum_id, enum_name));
		m_enumname2enumid.insert(std::make_pair(enum_name, enum_id));
		m_enum_const_cache.addEnum(enum_id, enum_name);

		std::list<EnumConstInfo> enum_const_info_list;
		if (!getEnumConstants(enum_name, enum_const_info_list)) {
			appendError("Enum constants for enum '" + enum_name + "' could not be found while opening DB.");
			return false;
		}
		std::list<EnumConstInfo>::const_iterator ci2 = 
			enum_const_info_list.begin();
		while (ci2 != enum_const_info_list.end()) {
			m_enum_const_cache.addEci(enum_id, enum_name, *ci2);
			++ci2;
		}
		
		++enum_counter;
		++ci;
	}


	return true;
}

bool BPTEMdFConnection::read_string(long string_index, std::string& outstr)
{

	/*
	OFFSET2STRING_map_t::const_iterator ci = m_offset2string_cache.find(string_index);
	if (ci != m_offset2string_cache.end()) {
		outstr = ci->second;
		return true;
	}
	*/
	/*
	unsigned char sLength[5];
	size_t bytes_read = read_bytes_string(sLength, m_strings_start + string_index, 5);
	if (bytes_read != 5) {
		return false;
	}

	unsigned long nLength;
	unsigned long string_position;
	if (m_schema_version == 0x01
	    || m_schema_version == 0x02) {
		nLength = (unsigned long) fourbytes2long(sLength);
		string_position = m_strings_start + string_index + 4;
	} else if (m_schema_version == 0x03) {
		int nBytesRead = varint2ulong(&(sLength[0]), &nLength);
		string_position = m_strings_start + string_index + nBytesRead;
	} else {
		ASSERT_THROW(false,
			     "Unknown schema version in BPT engine: " + long2string(m_schema_version));
	}
	*/
	const unsigned long longest_string_to_read_in_one_go = 60;
	const unsigned long bytes_to_read_at_first = 5 + longest_string_to_read_in_one_go;

	size_t bytes_read = read_bytes_string(m_string_buffer, m_strings_start + string_index, bytes_to_read_at_first);
	if (bytes_read != bytes_to_read_at_first) {
		return false;
	}

	unsigned long nLength;
	unsigned long string_position;
	const unsigned char *pStringBufferStringStart = 0;
	if (m_schema_version == 0x01
	    || m_schema_version == 0x02
	    || m_schema_version == 0x05) {
		nLength = (unsigned long) fourbytes2long(m_string_buffer);
		string_position = m_strings_start + string_index + 4;
		pStringBufferStringStart = m_string_buffer + 4;
	} else if (m_schema_version == 0x03
		   || m_schema_version == 0x07) {
		int nBytesRead = varint2ulong(&(m_string_buffer[0]), &nLength);
		string_position = m_strings_start + string_index + nBytesRead;
		pStringBufferStringStart = m_string_buffer + nBytesRead;	
	} else {
		ASSERT_THROW(false,
			     "Unknown schema version in BPT engine: " + long2string(m_schema_version));
	}
	
	if (nLength == 0) {
		outstr = "";
		/*
		m_offset2string_cache.insert(std::make_pair(string_index, outstr));
		m_string2offset_cache.insert(std::make_pair(outstr, string_index));
		*/
		return true;
	} else if (nLength < longest_string_to_read_in_one_go) {
		outstr.assign((const char*) pStringBufferStringStart, nLength);
		return true;
	} else if (nLength < STRING_BUFFER_LENGTH) {
		size_t bytes_read = read_bytes_string(m_string_buffer, string_position, nLength);
		if (bytes_read != nLength) {
			return false;
		} else {
			outstr.assign((const char*)m_string_buffer, nLength);
            
			/*
             m_offset2string_cache.insert(std::make_pair(string_index, outstr));
             m_string2offset_cache.insert(std::make_pair(outstr, string_index));
             */
            
			return true;
		}
    } else {
		unsigned char *szStr = (unsigned char*) malloc(nLength);
		size_t bytes_read = read_bytes_string(szStr, string_position, nLength);
		if (bytes_read != nLength) {
			free(szStr);
			return false;
		} else {
			outstr.assign((const char*)szStr, nLength);
			free(szStr);

			/*
			m_offset2string_cache.insert(std::make_pair(string_index, outstr));
			m_string2offset_cache.insert(std::make_pair(outstr, string_index));
			*/

			return true;
		}
	}
}

BPTTable *BPTEMdFConnection::getTableOrIndex(const std::string& index_name_or_otn)
{
	BPTTable *pTable = getTable(index_name_or_otn, false);
	if (pTable != 0) {
		return pTable;
	} else {
		pTable = getIndex(index_name_or_otn, false);
                if (pTable != 0) {
			return pTable;
		} else {
			appendError("Could not find table data for index or object type '" + index_name_or_otn + "'");
			return 0;
                }
	}
}


BPTTable *BPTEMdFConnection::getTable(const std::string& OTN, bool bReportError)
{
	if (m_pSchema == 0) {
		appendError("Schema not yet set while looking for object type '" + OTN + "'.");
		return 0;
	}

	bool bOTExists;
	id_d_t dummy_object_type_id;
	eObjectRangeType dummy_objectRangeType;
	eMonadUniquenessType dummy_monadUniquenessType;
	if (!objectTypeExists(OTN,
			      bOTExists,
			      dummy_object_type_id,
			      dummy_objectRangeType,
			      dummy_monadUniquenessType)) {
		if (bReportError) {
			appendError("Error finding out whether Object type '" + OTN + "' exists.");
		}
		return 0;
	} 

	if (!bOTExists) {
		if (bReportError) {
			appendError("Object type '" + OTN + "' does not exist.");
		}
		return 0;
	}

	OTN2BPTTable_map_t::iterator it = m_table_map.find(OTN);
	if (it == m_table_map.end()) {
		BPTTable *pTable = new BPTTable(m_pSchema, this, OTN, false);
		m_table_map.insert(std::make_pair(OTN, pTable));
		return pTable;
	} else {
		return it->second;
	}
}


BPTTable *BPTEMdFConnection::getIndex(const std::string& index_table_name, bool bReportError)
{
	if (m_pSchema == 0) {
		return 0;
	}

	bool bIndexExists;
	if (!indexExists(index_table_name, bIndexExists)) {
		if (bReportError) {
			appendError("Error finding out whether Index table '" + index_table_name + "' exists.");
		}
		return 0;
	}
	
	if (!bIndexExists) {
		if (bReportError) {
			appendError("Index table '" + index_table_name + "' does not exist.");
		}
		return 0;
	}

	OTN2BPTTable_map_t::iterator it = m_index_map.find(index_table_name);
	if (it == m_index_map.end()) {
		BPTTable *pTable = new BPTTable(m_pSchema, this, index_table_name, true);
		m_index_map.insert(std::make_pair(index_table_name, pTable));
		return pTable;
	} else {
		return it->second;
	}
}






