/** Check whether enumeration exists, based on id_d
 *@internal
 *
 * @param enum_id The id_d of the enum to find.
 * @param result Used to return true if it is there, false if it is not.  
 * @param enum_name Used to return the name of the enumeration.  Only valid
 *        if \p result is true.
 * @return True on no database error, false if a database error occurred.
 */
bool BPTEMdFDB::enumExists(id_d_t enum_id,
			   /* out */ bool& result,
			   /* out */ std::string& enum_name)
{
	if (pConn == 0)
		return false;
	else {
		// Strip the lower bits off that aren't part of the enum_id
		enum_id = STRIP_ENUM_ID_OF_LOWER_BITS(enum_id);

		if (!((BPTEMdFConnection*)pConn)->enumExists(enum_id,
							     result,
							     enum_name)) {
			DEBUG_X_FAILED("BPTEMdFDB::enumExists", "pConn->enumExists()");
			return false;
		}


		// no matter whether we found the enum or not.
		return true;
	}
}

/** Check whether enumeration exists, based on enumeration name
 *@internal
 *
 * @param enum_name The name of the enum to find.
 * @param result Used to return true if it is there, false if it is not.
 * @param enum_id Used to return the id_d of the enumeration.  Only valid 
 *        if \p result is true.
 * @return True on no database error, false if a database error occurred.
 */
bool BPTEMdFDB::enumExists(const std::string& enum_name, 
			   /* out */ bool& result,
			   /* out */ id_d_t& enum_id)
{
	if (pConn == 0)
		return false;
	else {
		if (!((BPTEMdFConnection*)pConn)->enumExists(enum_name,
							     result,
							     enum_id)) {
			DEBUG_X_FAILED("BPTEMdFDB::enumExists", "pConn->enumExists()");
			return false;
		}

		// Strip the lower bits off that aren't part of the enum_id
		enum_id = STRIP_ENUM_ID_OF_LOWER_BITS(enum_id);

		// no matter whether we found the enum or not.
		return true;
	}
}

/** Get the default constant in an enumeration.
 *@internal
 *
 * @param enum_id The id_d of the enumeration.
 * @param result Used to return true if it is there, false if it is not.
 * @param default_constant_name Used to return the name of the default
 *        constant.  Only valid if \p result is true.
 * @return True on no database error, false if a database error occurred.
 */
bool BPTEMdFDB::getDefault(id_d_t enum_id, 
			   /* out */ bool& result,
			   /* out */ std::string& default_constant_name)
{
	if (pConn == 0)
		return false;
	else {
		result = false;

		std::string enum_name;
		std::list<EnumConstInfo> enum_constants;
		if (!getEnumConstants(enum_id, enum_constants)) {
			DEBUG_X_IS_WRONG("BPTEMdFDB::getDefault", "Could not get enum constants from enum: " + id_d2string(enum_id));
			return false;
		}
		std::list<EnumConstInfo>::const_iterator ciec = enum_constants.begin();
		while (ciec != enum_constants.end()) {
			std::string ec_name = ciec->getName();
			bool bEnumConstExists;
			long enum_value;
			bool bIsDefault = false;
			if (!(enumConstExists(ec_name,
					      enum_id,
					      bEnumConstExists,
					      enum_value,
					      bIsDefault))) {
				DEBUG_X_FAILED("BPTEMdFDB::getDefault", "finding enum: " + ec_name);
				result = false;
				return false;
			}

			if (!bEnumConstExists) {
				DEBUG_X_FAILED("BPTEMdFDB::getDefault", "finding enum: " + ec_name);
				result = false;
				return false;
			}

			if (bIsDefault) {
				default_constant_name = ec_name;
				result = true;
				return true;
			}
			++ciec;
		}

		// We did not find any default.
		result = false;
		// no matter whether we found the default or not.
		return true;
	}
}


