/** Check if connection to DB backend is OK.
 *
 * Just calls EMdFConnection::connectionOk() (or its polymorphic
 * instance).
 *
 * @see EMdFConnection::connectionOk()
 * 
 * @return True if connection is alive, false if not.
 */
bool BPTEMdFDB::connectionOk(void)
{
	if (strcmp_nocase(m_current_db_name, "emdf") == 0) {
		// Treat the dummy-database 'emdf' as 'always good'.
		return true;
	} else if (pConn == 0) {
		return false;
	} else {
		return pConn->connectionOk();
	}
}

/** Get objects having monads in a monad set
 *@internal
 *
 * Returns all the objects that have monads overlapping with a
 * specified monad set.  This is used to implement the MQL statement
 * "SELECT OBJECTS HAVING MONADS IN."  The monad set can be anything;
 * it need not be contiguous, but it must be non-empty.
 *
 * Note that this is not the same as objects that fit completely
 * inside the set of monads... it is objects that overlap with it.
 *
 * This is not the public method; it is protected, and is used by the
 * other version of this method.
 *
 * @param object_type_name the name of the object type that holds the
 * objects.
 *
 * @param monad_ms the monad set to use in the search
 *
 * @param objects_already_seen A set of object id_ds of objects which
 * we have already seen.
 *
 * @param objectRangeType the eObjectRangeType of the object type
 *
 * @param result the resulting Table.  Has the same signature as the
 * SELECT OBJECTS HAVING MONADS IN statement (see the MQL User's
 * Guide).
 *
 * @return true on no DB error, false otherwise.
 */
bool BPTEMdFDB::getObjectsHavingMonadsInMonadSet(const std::string object_type_name,
						 const SetOfMonads& monad_ms,
						 std::set<id_d_t>& objects_already_seen,					      
						 eObjectRangeType objectRangeType,
						 /* out */ Table& result)
{
	DEBUG_X_IS_WRONG("BPTEMdFDB::getObjectsHavingMonadsInMonadSet", "Not implemented.  Shouldn't be necessary.");
	return false;
}


/** The maximum number of MonadSetElements to have in a WHERE clause.
 */
#define MAX_MSES (200) 

/** Get objects having monads in monad set.
 *@internal
 *
 * Returns all the objects that have monads overlapping with a
 * specified monad set.  This is used to implement the MQL statement
 * "SELECT OBJECTS HAVING MONADS IN."  The monad set can be anything;
 * it need not be contiguous, but it must be non-empty.
 *
 * Note that this is not the same as objects that fit completely
 * inside the set of monads... it is objects that overlap with it.
 *
 * This is actually what is called from the MQL engine; the other
 * version of this method is used by this method to do the grunt work.
 *
 * @param object_type_name the name of the object type that holds the
 * objects.
 *
 * @param monad_ms the monad set to use in the search
 *
 * @param objectRangeType the eObjectRangeType of the object type
 *
 * @param result the resulting Table.  Has the same signature as the
 * SELECT OBJECTS HAVING MONADS IN statement (see the MQL User's
 * Guide).
 *
 * @return true on no DB error, false otherwise.
 */
bool BPTEMdFDB::getObjectsHavingMonadsInMonadSet(const std::string object_type_name,
						 const SetOfMonads& monad_ms,
						 eObjectRangeType objectRangeType,
						 /* out */ Table& result)
{
	if (pConn == 0)
		return false;
	else {
		// Normalize object type name
		std::string OTN = normalizeOTName(object_type_name);

		bool bDBHasMonadSetLengthColumn = ((BPTEMdFConnection*)(pConn))->hasMonadSetLengthColumn();
		
		std::list<std::string> columns_to_get;
		columns_to_get.push_back("object_id_d");
		columns_to_get.push_back("first_monad");
		
		
		// Build and execute query
		if (objectRangeType == kORTSingleRange) {
			if (bDBHasMonadSetLengthColumn) {
				columns_to_get.push_back("som_length");
			} else {
				columns_to_get.push_back("last_monad");
			}
		} else if (objectRangeType == kORTMultipleRange) {
			columns_to_get.push_back("monads");
			if (bDBHasMonadSetLengthColumn) {
				columns_to_get.push_back("som_length");
			}
		}
		
		// Largest object length
		monad_m largest_object_length;
		if (!getLargestObjectLength(OTN, 
					    objectRangeType,
					    largest_object_length)) {
			DEBUG_X_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet", "getting largest object length");
			return false;
		}
		
		SetOfMonads filledSetOfMonads(monad_ms.fillGaps(largest_object_length));
		
		if (!((BPTEMdFConnection*)pConn)->execQuery(OTN,
							    kQueryKindHavingMonadsIn,
							    &filledSetOfMonads,
							    "monads",
							    columns_to_get,
							    0)) {
			DEBUG_BPT_QUERY_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet", OTN, monad_ms.toString(), joinList(", ", columns_to_get), "");
			return false;
		}
		
		
		try {
			id_d_t oid;  
			monad_m mse_first;
			monad_m mse_last;
			bool bMoreRows = pConn->hasRow();
			while (bMoreRows) {
				SetOfMonads som;
				// Get data from tuple
				if (!pConn->accessTuple(0, oid)) {
					DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
					return false;
				}
				if (!pConn->accessTuple(1, mse_first)) {
					DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
					return false;
				}
				if (objectRangeType == kORTSingleMonad) {
					mse_last = mse_first;
					som.add(mse_first, mse_last);
				} else if (objectRangeType == kORTSingleRange) {
					if (bDBHasMonadSetLengthColumn) {
						monad_m som_length;
						if (!pConn->accessTuple(2, som_length)) {
							DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
							return false;
						}
						// For kORTSingleRange
						// objects, the
						// som_length is the
						// true length, and so
						// we don't need to
						// subtract 1.

						mse_last = mse_first + som_length;
					} else {
						if (!pConn->accessTuple(2, mse_last)) {
							DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
							return false;
						}
					}
					som.add(mse_first, mse_last);
				} else {
					if (bDBHasMonadSetLengthColumn) {
						monad_m som_length;
						if (!pConn->accessTuple(3, som_length)) {
							DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
							return false;
						}
						// For
						// kORTMultipleRange
						// objects, the
						// som_length is
						// either 0 (because
						// we need to consult
						// the monads string),
						// or it is the true
						// length + 1, and so
						// we need to subtract
						// 1.

						if (som_length == 0) {
							std::string monads_string;
							if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(2, monads_string)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
								return false;
							}
							som.fromCompactStringFM(monads_string, mse_first);
						} else {
							// som_length != 0, so we can skip reading monads_string.
							mse_last = mse_first + som_length - 1;
							som.add(mse_first, mse_last);
						}
					} else {
						std::string monads_string;
						if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(2, monads_string)) {
							DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
							return false;
						}
						som.fromCompactStringFM(monads_string, mse_first);
					}
				}

				// Construct data
				// Only add if it actually meets the criteria
				SetOfMonads intersection = SetOfMonads::intersect(som, monad_ms);
				if (!intersection.isEmpty()) {
					// Find out which monad to add
					monad_m monad_to_add = intersection.first();
					
					// Add to result
					result.startNewRow();
					result.append(object_type_name);
					result.append(monad_m2string(monad_to_add));
					result.append(id_d2string(oid));
				}

				// Get next tuple
				if (!pConn->getNextTuple(bMoreRows)) {
					DEBUG_GET_NEXT_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
					return false;
				}
			}
		} catch (EMdFNULLValueException e) {
			DEBUG_NULL_VALUE_EXCEPTION("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
			// There was a NULL value exception, hence we return an error
			return false;
		}

    
		// Release results
		pConn->finalize();

		// If we got this far, the command was a success.
		return true;
	}
}




/** Get objects having monads in monad set.
 *@internal
 *
 * Returns all the objects that have monads overlapping with a
 * specified monad set.  This is used to implement the MQL statement
 * "SELECT OBJECTS HAVING MONADS IN."  The monad set can be anything;
 * it need not be contiguous, but it must be non-empty.
 *
 * Note that this is not the same as objects that fit completely
 * inside the set of monads... it is objects that overlap with it.
 *
 * This is actually what is called from the MQL engine; the other
 * version of this method is used by this method to do the grunt work.
 *
 * @param object_type_name the name of the object type that holds the
 * objects.
 *
 * @param object_type_id the id_d of the object type
 *
 * @param objectRangeType the eObjectRangeType of the object type
 *
 * @param monad_ms the monad set to use in the search
 *
 * @param features_to_get a list of the features to get.
 *
 * @param pInst Result as an Inst
 *
 * @return true on no DB error, false otherwise.
 */
bool BPTEMdFDB::getObjectsHavingMonadsIn(const std::string object_type_name,
					 id_d_t object_type_id,
					 eObjectRangeType objectRangeType,	
					 const SetOfMonads& monad_ms,
					 const SetOfMonads& all_m_1,
					 const std::list<FeatureInfo>& features_to_get,
					 const std::string& monad_set_name,
					 /* Out */ Inst *pInst)
{
	if (pConn == 0) {
		return false;
	} else {
		// Normalize object type name
		std::string OTN = normalizeOTName(object_type_name);

		bool bDBHasMonadSetLengthColumn = ((BPTEMdFConnection*)pConn)->hasMonadSetLengthColumn();

		// Are we doing a normal "monads" Inst or a "monad-set-feature" Inst
		std::string locase_monad_set_name;
		str_tolower(monad_set_name, locase_monad_set_name);

		bool bMonadSetIsFeature = strcmp_nocase(locase_monad_set_name, "monads") != 0;

		
		FastSetOfMonads original_som(monad_ms);

		// Get monad uniqueness type
		id_d_t dummy_object_type_id;
		bool dummy_bExists;
		eObjectRangeType dummyRangeType;
		eMonadUniquenessType monadUniquenessType;
		if (!objectTypeExists(object_type_name, 
				      dummy_bExists,
				      dummy_object_type_id,
				      dummyRangeType,
				      monadUniquenessType)) {
			return false;
		}

		// Largest object length
		monad_m largest_object_length;
		if (bMonadSetIsFeature) {
			largest_object_length = 1;
		} else {
			if (!getLargestObjectLength(OTN, 
						    objectRangeType,
						    largest_object_length)) {
				DEBUG_X_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn", "getting largest object length");
				return false;
			}
		}
		
		std::list<std::string> columns_to_get;
		columns_to_get.push_back("object_id_d");
		if (bMonadSetIsFeature) {
			columns_to_get.push_back(encodeFeatureNameBPT(locase_monad_set_name));
			columns_to_get.push_back("first_monad_mdf_" + locase_monad_set_name);
		} else if (objectRangeType == kORTSingleRange) {
			columns_to_get.push_back("first_monad");
			if (bDBHasMonadSetLengthColumn) {
				columns_to_get.push_back("som_length");
			} else {
				columns_to_get.push_back("last_monad");
			}
		} else if (objectRangeType == kORTMultipleRange) {
			columns_to_get.push_back("first_monad");
			columns_to_get.push_back("monads");
			if (bDBHasMonadSetLengthColumn) {
				columns_to_get.push_back("som_length");
			}
		} else if (objectRangeType == kORTSingleMonad) {
			columns_to_get.push_back("first_monad");
		} else {
			ASSERT_THROW(false, "Unknown objectRangeType:" + long2string(objectRangeType));
		}
		

		// ****************************************************
		//
		// Preliminaries
		//
		// ****************************************************

		// Make string of features to get
		std::string str_features_to_get;
		std::vector<id_d_t> column_types_vec; // basec on columns to get
		std::vector<bool> feature_is_monads_vec; // based on monads
		std::list<FeatureInfo>::const_iterator feat_ci(features_to_get.begin());
		std::list<FeatureInfo>::const_iterator cend(features_to_get.end());
		std::vector<StringSetCache*> string_set_caches_vec(features_to_get.size(), 0);
		while (feat_ci != cend) {
			// Get lowercase name
			std::string locase_name;
			str_tolower(feat_ci->getName(), locase_name);
			bool bIsMonads = false;
			
			// Is it self?
			// TODO: We should check for computed status when we add
			// ability to do computed features.
			std::string encoded_feature_name;
			if (locase_name == "self") {
				encoded_feature_name = "object_id_d";
				columns_to_get.push_back("object_id_d");

				column_types_vec.push_back(FEATURE_TYPE_ID_D);

				feature_is_monads_vec.push_back(false);

			} else if (locase_name == "monads") {
				bIsMonads = true;
				encoded_feature_name = "monads";
				feature_is_monads_vec.push_back(true);	
				if (objectRangeType == kORTSingleRange) {
					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);
					columns_to_get.push_back("first_monad");
					if (bDBHasMonadSetLengthColumn) {
						columns_to_get.push_back("som_length");
						column_types_vec.push_back(FEATURE_TYPE_INTEGER);
					} else {
						columns_to_get.push_back("last_monad");
						column_types_vec.push_back(FEATURE_TYPE_INTEGER);
					}
					// column_types_vec is based
					// on columns, not
					// features.

					


				} else if (objectRangeType == kORTMultipleRange) {
					columns_to_get.push_back("first_monad");
					columns_to_get.push_back("monads");

					// column_types_vec is based
					// on columns, not
					// features.
					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);
					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);


					if (bDBHasMonadSetLengthColumn) {
						columns_to_get.push_back("som_length");
						// column_types_vec
						// is based on
						// columns, not
						// features.
						column_types_vec.push_back(FEATURE_TYPE_INTEGER);
					}
				} else if (objectRangeType == kORTSingleMonad) {
					columns_to_get.push_back("first_monad");
					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);
				} else {
					ASSERT_THROW(false, "Unknown objectRangeType:" + long2string(objectRangeType));
				}
			} else {
				encoded_feature_name = encodeFeatureName(locase_name);
				columns_to_get.push_back(encoded_feature_name);
				/*
				if (featureTypeIdIsFromSet(ci->getType())) {
				if (!loadStringSetIntoCacheBPT(OTN,
								    object_type_id,
								    locase_name)) {
						DEBUG_X_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn()", ("getting string set cache for " + OTN + "." + locase_name));
						return false;
					}
					
					StringSetCache *pSSC = m_string_sets_cache->getSSC(object_type_id, encodeFeatureName(locase_name));
					string_set_caches_vec[feature_names_index] = pSSC;
				}
				*/

				// Add type to column_types_vec
				id_d_t feature_type = feat_ci->getType();
				column_types_vec.push_back(feature_type);
				
				
				
				if (featureTypeIdIsSOM(feat_ci->getType())
				    && !bIsMonads) {
					columns_to_get.push_back("first_monad_" + encoded_feature_name);
					column_types_vec.push_back(FEATURE_TYPE_INTEGER);

					// feature_is_monads_vec must
					// only be true for the
					// feature "monads", not
					// other monad set features.
					feature_is_monads_vec.push_back(false);
				} else {
					feature_is_monads_vec.push_back(false);
				}
			}
			
			
			// Advance iterators
			++feat_ci;
		}
		

		SetOfMonads filled_monad_set(monad_ms.fillGaps(largest_object_length));

		LOG_WRITE_TIME("BPTEMdFDB::getObjectsHavingMonadsIn", "Query starting.");
		
		if (!((BPTEMdFConnection*)pConn)->execQuery(OTN,
							    kQueryKindHavingMonadsIn,
							    &filled_monad_set,
							    monad_set_name,
							    columns_to_get,
							    0)) {
			DEBUG_BPT_QUERY_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn", OTN, monad_ms.toString(), joinList(", ", columns_to_get), "");
			return false;
		}


		LOG_WRITE_TIME("BPTEMdFDB::getObjectsHavingMonadsIn", "Query finished.");
		int column_index;
		int no_of_features_to_get = features_to_get.size();

		LOG_WRITE_TIME("BPTEMdFDB::getObjectsHavingMonadsIn", "Retrieval starting.");
		InstObject *pObj = 0;
		try {
			bool bMoreRows = pConn->hasRow();

			
			int feature_column_index;
			if (bMonadSetIsFeature) {
				feature_column_index = 3;
			} else if (objectRangeType == kORTSingleMonad) {
				feature_column_index = 2;
			} else if (objectRangeType == kORTSingleRange) {
				feature_column_index = 3;
			} else if (objectRangeType == kORTMultipleRange) {
				if (bDBHasMonadSetLengthColumn) {
					feature_column_index = 4;
				} else {
					feature_column_index = 3;
				}
			} else {
				ASSERT_THROW(false,
					     "Unknown objectRangeType.");
			}

			int no_of_feature_columns_to_get = columns_to_get.size() - feature_column_index;
			
			while (bMoreRows) {
				// Declare this pFeature_values array of dummy EMdFValue objects.
				EMdFValue *pFeature_values;
				if (no_of_features_to_get > 0) {
					// This uses the () constructor, which gives us a kEVInt with 
					// value 0.
					pFeature_values = (EMdFValue *) pInst->allocate(sizeof(EMdFValue)*no_of_features_to_get);
					/*
					  for (int i = 0; i < no_of_features_to_get; ++i) {
					  // Use placement new operator (p. 255 in TC++PL 3rd ed.)
					  new (&pFeature_values[i]) EMdFValue();
					  }
					*/
				} else {
					pFeature_values = 0;
				}

				// Get object id_d
				id_d_t oid;
				if (!pConn->accessTuple(0, oid)) {
					DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
					return false;
				}

				bool bGetObject = false;
				SetOfMonads *pSom = 0; 
				monad_m mse_first, mse_last;

				if (bMonadSetIsFeature) {
					std::string monads_string;
					if (!pConn->accessTuple(1, monads_string)) {
						DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
						return false;
					}
					long som_first_monad;
					if (!pConn->accessTuple(2, som_first_monad)) {
						DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
						return false;
					}
					pSom = new SetOfMonads();
					// std::cerr << "UP239: som_first_monad = '" << som_first_monad << ", monads_string = '" << monads_string << "'" << std::endl;
					pSom->fromCompactStringFM(monads_string, som_first_monad);
					// std::cerr << "UP239.2: pSom = " << pSom->toString() << std::endl;

					if (FastSetOfMonads::overlap(*pSom, original_som)) {
						mse_first = som_first_monad;
						mse_last = pSom->last();
						bGetObject = true;
					} else {
						delete pSom;
					}
					
					// std::cerr << "UP430: pSOM = " << pSom->toString() << ", first = " << pSom->first() << ", mse_first = " << mse_first << ", last = " << pSom->last() << '\n';


				} else {	
					if (!pConn->accessTuple(1, mse_first)) {
						DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
						return false;
					}

					if (objectRangeType == kORTSingleMonad) {
						/* If this is WITH SINGLE MONAD OBJECTS, then we don't 
						 * retrive mse_last.  Instead, we just get it
						 * from mse_first.
						 */
						mse_last = mse_first;
						if (original_som.isMemberOf(mse_first)) {
							bGetObject = true;
						}
					}  else if (objectRangeType == kORTSingleRange) {
						if (bDBHasMonadSetLengthColumn) {
							monad_m som_length;
							if (!pConn->accessTuple(2, som_length)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
								return false;
							}
							// For kORTSingleRange
							// objects, the
							// som_length is the
							// true length, and so
							// we don't need to
							// subtract 1.
							
							mse_last = mse_first + som_length;
						} else {
							if (!pConn->accessTuple(2, mse_last)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
								return false;
							}
						}
						if (original_som.hasMonadsInRange(mse_first, mse_last)) {
							bGetObject = true;
						}
					} else {
						// kORTMultipleRange
						if (bDBHasMonadSetLengthColumn) {
							monad_m som_length;
							if (!pConn->accessTuple(3, som_length)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
								return false;
							}
							// For
							// kORTMultipleRange
							// objects, the
							// som_length is
							// either 0 (because
							// we need to consult
							// the monads string),
							// or it is the true
							// length + 1, and so
							// we need to subtract
							// 1.
							
							if (som_length == 0) {
								std::string monads_string;
								if (!pConn->accessTuple(2, monads_string)) {
									DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
									return false;
								}
								pSom = new SetOfMonads(monads_string, mse_first);
								if (FastSetOfMonads::overlap(*pSom, original_som)) {
									mse_last = pSom->last();
									bGetObject = true;
								} else {
									delete pSom;
								}
							} else {
								// som_length != 0, so we can skip reading monads_string.
								mse_last = mse_first + som_length - 1;
								pSom = new SetOfMonads(mse_first, mse_first);
								if (original_som.hasMonadsInRange(mse_first, mse_last)) {
									bGetObject = true;
								} else {
									delete pSom;
								}
							}
						} else {
							
							std::string monads_string;
							if (!pConn->accessTuple(2, monads_string)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
								return false;
							}
							pSom = new SetOfMonads(monads_string, mse_first);
							if (FastSetOfMonads::overlap(*pSom, original_som)) {
								mse_last = pSom->last();
								bGetObject = true;
							} else {
								delete pSom;
							}
						}
					}
				}

				// This is only necessary if we both:
				// (a) do this loop with inexact
				// monad-data, and (b) may have
				// overlap between different database
				// searches for the same stretch of
				// monads.

				// However, as it turns out, while we
				// do not work with inexact monad-data
				// (a), we might have overlap between
				// different database searches for the
				// same stretch of monads (b). This is
				// because kQueryKindHavingMonadsIn
				// automatically subtracts the largest
				// object length and thus looks for
				// many more monads than those inside
				// each MSE in the input SOM. Thus, if
				// we have two MSEs which are less
				// distance apart than the largest
				// object length, we might get the
				// same object twice.
				if (bGetObject) {
					if (pInst->hasObject(mse_first, oid)) {
						bGetObject = false;
						delete pSom;
					}
				}
				if (bGetObject) {
					// Get feature values
					if (no_of_features_to_get > 0) {
						std::string value_str;
						long value_long;
						int feature_index = 0;
						for (column_index = 0; column_index < no_of_feature_columns_to_get; ++column_index, ++feature_index) {
							//EMdFValue *pValue = 0;
							id_d_t feature_type = column_types_vec[column_index];
							if (featureTypeIdIsListOf(feature_type)) {
								if (!pConn->accessTuple(feature_column_index + column_index, 
											value_str)) {
									DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
									return false;
								}
								IntegerList *pIntegerList = new IntegerList(value_str, DEFAULT_LIST_DELIMITER);
								switch (feature_type & FEATURE_TYPE_TYPE_MASK) {
								case FEATURE_TYPE_LIST_OF_INTEGER:
									new (&pFeature_values[feature_index]) EMdFValue(kEVListOfInteger, pIntegerList);
									break;
								case FEATURE_TYPE_LIST_OF_ID_D:
									new (&pFeature_values[feature_index]) EMdFValue(kEVListOfID_D, pIntegerList);
									break;
								case FEATURE_TYPE_LIST_OF_ENUM:
									// We do not translate to enum constants, since this is done in the MQL layer.
									new (&pFeature_values[feature_index]) EMdFValue(kEVListOfInteger, pIntegerList);
									break;
								default:
									ASSERT_THROW(false, "Unknown FEATURE_TYPE");
									break;
								}
							} else {
								switch (feature_type & FEATURE_TYPE_TYPE_MASK) {
								case FEATURE_TYPE_ASCII:
								case FEATURE_TYPE_STRING:
									if (!pConn->accessTuple(feature_column_index + column_index, 
												value_str)) {
										DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
										return false;
									}

									/*
									  if (featureTypeIdIsFromSet(feature_type)
									  && string_set_caches_vec[feature_index] != 0) {
									  std::string newValue;
									  id_d_t id_d = string2long(value_str);
									  if (!string_set_caches_vec[feature_index]->getStringFromID_D(id_d, newValue)) {
									  DEBUG_X_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn", "Getting string from set.");
									  pConn->finalize();
									  return false;
									  }
									  new (&pFeature_values[feature_index]) EMdFValue(newValue);
									  } else {
									*/
									new (&pFeature_values[feature_index]) EMdFValue(value_str);
									/*
									  }
									*/
									break;
								case FEATURE_TYPE_INTEGER:
									if (!pConn->accessTuple(feature_column_index + column_index, 
												value_long)) {
										DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
										return false;
									}
									new (&pFeature_values[feature_index]) EMdFValue(kEVInt, value_long);
									break;
								case FEATURE_TYPE_ID_D:
									if (!pConn->accessTuple(feature_column_index + column_index, 
												value_long)) {
										DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
										return false;
									}
									new (&pFeature_values[feature_index]) EMdFValue(kEVID_D, value_long);
									break;
								case FEATURE_TYPE_SET_OF_MONADS:
									if (feature_is_monads_vec[feature_index]) {
										SetOfMonads som;

										monad_m feature_mse_first, feature_mse_last;

										if (!pConn->accessTuple(feature_column_index + column_index, feature_mse_first)) {
											DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
											return false;
										}


										if (objectRangeType == kORTSingleMonad) {
											/* If this is WITH SINGLE MONAD OBJECTS, then we don't 
											 * retrive mse_last.  Instead, we just get it
											 * from mse_first.
											 */
											som.add(feature_mse_first);
										}  else if (objectRangeType == kORTSingleRange) {
											if (bDBHasMonadSetLengthColumn) {
												monad_m feature_som_length;
												++column_index;
												if (!pConn->accessTuple(feature_column_index + column_index, feature_som_length)) {
													DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
													delete pSom;
													return false;
												}
												// For kORTSingleRange
												// objects, the
												// som_length is the
												// true length, and so
												// we don't need to
												// subtract 1.
												
												feature_mse_last = feature_mse_first + feature_som_length;
											} else {
												++column_index;
												if (!pConn->accessTuple(feature_column_index + column_index, feature_mse_last)) {
													DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
													delete pSom;
													return false;
												}
											}
											som.add(feature_mse_first, feature_mse_last);
										} else if (objectRangeType == kORTMultipleRange) {
											if (bDBHasMonadSetLengthColumn) {
												monad_m feature_som_length;
												++column_index;
												if (!pConn->accessTuple(feature_column_index + column_index + 1, feature_som_length)) {
													DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
													return false;
												}
												// For
												// kORTMultipleRange
												// objects, the
												// som_length is
												// either 0 (because
												// we need to consult
												// the monads string),
												// or it is the true
												// length + 1, and so
												// we need to subtract
												// 1.
											
												if (feature_som_length == 0) {
													std::string feature_monads_string;
													if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(feature_column_index + column_index, feature_monads_string)) {
														DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
														return false;
													}
													som.fromCompactStringFM(feature_monads_string, feature_mse_first);
												} else {
													// som_length != 0, so we can skip reading monads_string.
													feature_mse_last = feature_mse_first + feature_som_length - 1;
													som.add(feature_mse_first, feature_mse_last);
												}
												++column_index;
											} else {
												std::string monads_string;
												++column_index;
												if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(feature_column_index + column_index, monads_string)) {
													DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
													delete pSom;
													return false;
												}
												som.fromCompactStringFM(monads_string, feature_mse_first);
											}
										} else {
											ASSERT_THROW(false, "Unknown objectRangeType:" + long2string(objectRangeType));
										}
										new (&pFeature_values[feature_index]) EMdFValue(som);
									} else {
										if (!pConn->accessTuple(feature_column_index + column_index, 
													value_str)) {
											DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
											return false;
										}
										if (!pConn->accessTuple(feature_column_index + column_index + 1, 
													value_long)) {
											DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
											return false;
										}
										{
											SetOfMonads som;
											som.fromCompactStringFM(value_str, value_long);
											new (&pFeature_values[feature_index]) EMdFValue(som);
										}
										// Skip over the first_monad_mdf_<feature-name> column
										++column_index;
									}
									break;
								case FEATURE_TYPE_ENUM:
									if (!pConn->accessTuple(feature_column_index + column_index, 
												value_long)) {
										DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
										return false;
									}
									new (&pFeature_values[feature_index]) EMdFValue(kEVEnum, value_long);
									break;
								default:
									ASSERT_THROW(false, "Unknown FEATURE_TYPE: " + long2string(feature_type) + " masked: " + long2string(feature_type & FEATURE_TYPE_TYPE_MASK));
									break;
								}
							}
						}
					}

					// Make new object
					// First allocate using Result Inst's allocator
					pObj = (InstObject*) pInst->allocate(sizeof(InstObject));
					if (bMonadSetIsFeature
					    || objectRangeType == kORTMultipleRange) {
						if (pSom->hasOnlyOneMSE()) {
							// Then use placement new operator (p. 255 in TC++PL 3rd ed.)
							// std::cerr << "UP501: About to create InstObject(" << mse_first << ", " << mse_last << ")\n";
							pObj = new(pObj) InstObject(oid, 
										    mse_first, mse_last,
										    pFeature_values, 
										    no_of_features_to_get); 
							delete pSom;
						} else {
							// Then use placement new operator (p. 255 in TC++PL 3rd ed.)
							// std::cerr << "UP502: About to create InstObject(" << pSom->toString() << ")\n";
							pObj = new(pObj) InstObject(oid, 
										    pSom, 
										    pFeature_values, 
										    no_of_features_to_get,
										    false); 
						} 
					} else {
						// Then use placement new operator (p. 255 in TC++PL 3rd ed.)
						// std::cerr << "UP503: About to create InstObject(" << mse_first << ", " << mse_last << ")\n";
						pObj = new(pObj) InstObject(oid, 
									    mse_first, mse_last,
									    pFeature_values, 
									    no_of_features_to_get); 
						delete pSom;
					}

					// Insert object in inst
					pInst->addObject(pObj, mse_first, mse_last);
				}

				// Get next tuple
				if (!pConn->getNextTuple(bMoreRows)) {
					DEBUG_GET_NEXT_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsIn");
					return false;
				}
			} // end of iteration over query-results
		} catch (EMdFNULLValueException e) {
			DEBUG_NULL_VALUE_EXCEPTION("BPTEMdFDB::getObjectsHavingMonadsIn");
			// There was a NULL value exception, hence we return an error
			return false;
		}

		// Write "retrieval finished" to log
		LOG_WRITE_TIME("BPTEMdFDB::getObjectsHavingMonadsIn", "Retrieval finished.");


		// finalize Result
		pInst->fillingIsDone();

		// If we got here, there were no errors.
		return true;
	}
}

/** The maximum number of conditions to have in a WHERE clause.
 */
#define MAX_CONDITIONS (2*200)

/** get Inst(T,Su).
 *
 *@internal
 *
 * Get an Inst(object type, Substrate).
 *
 * This is the entry point into BPTEMdFDB; the other getInst() is used by
 * this method.
 *
 * Actually, the substrate is not queried monad set element-for-monad
 * set element: Su.first()..Su.last() is queried instead, thus leaving
 * out any gaps.  The MQL engine will filter them out.
 *
 * @param object_type_name the name of the object type
 * 
 * @param object_type_id the id_d_t of the object type; must be for
 * the same object type as \p object_type_name .
 *
 * @param Su the substrate within which to search.
 *
 * @param all_m_1 the all_m-1 object for the database.
 *
 * @param pre_query_string an SQL string, suitable for putting in a
 * WHERE condition, that puts constraints on the objects queries.
 * Must use "OS.mdf_<feature-name>" in comparisons.  Can only use the
 * OT_objects table for the object type specified with
 * object_type_name.
 *
 * @param features_to_get a list of the features to get.
 *
 * @param monad_set_name the name of the monad set to use. If
 * "monads", then the monad set of which the object consists is
 * used. Otherwise, the string must refer to a feature on the object
 * type which is a set of monads.
 *
 * @param ms_operation Either kMSROPartOf or kMSROStartsIn
 *
 * @param Result the Inst to get back.
 *
 * @return true on no DB error, false otherwise.
 */
bool BPTEMdFDB::getInst(const std::string& object_type_name,
			id_d_t object_type_id,
			const SetOfMonads& Su,
			const SetOfMonads& all_m_1,
			const std::string& pre_query_string,
			EMdFFFeatures *pre_query_constraints,
			const std::list<FeatureInfo>& features_to_get,
			const std::string& monad_set_name,
			eMonadSetRelationOperation ms_operation,
			/* out */ Inst& Result)
{	
	if (pConn == 0) {
		return false;
	} else {
		// Get range type
		eObjectRangeType objectRangeType;
		if (!getOTObjectRangeType(object_type_name, objectRangeType)) {
			DEBUG_X_FAILED("BPTEMdFDB::getInst", "getting range type of object type " + object_type_name);
			return false;
		}

		// Get Inst
		if (!getInstLocalBPT(object_type_name,
				     object_type_id,
				     Su,
				     all_m_1,
				     pre_query_constraints,
				     features_to_get,
				     monad_set_name,
				     objectRangeType,
				     ms_operation,
				     Result)) {
			return false;
		}
    
		// If we got this far, the command was as success.
		return true;
	}
}


/** get Inst(T,Su)
 *@internal
 *
 * Get an Inst(object type, Substrate), within a range
 * first_monad..last_monad.
 *
 * This is not the public entry point into BPTEMdFDB; the other getInst()
 * uses this method.
 *
 * @param object_type_name the name of the object type
 * 
 * @param object_type_id the id_d_t of the object type; must be for
 * the same object type as \p object_type_name .
 *
 * @param first_monad the first monad to query
 *
 * @param last_monad the last monad to query (everything in between
 * first_monad and last_monad will be queried)
 *
 * @param all_m_1 the all_m-1 object for the database.
 *
 * @param pre_query_string an SQL string, suitable for putting in a
 * WHERE condition, that puts constraints on the objects queries.
 * Must use "OS.mdf_<feature-name>" in comparisons.  Can only use the
 * OT_objects table for the object type specified with
 * object_type_name.
 *
 * @param features_to_get a list of the features to get.
 *
 * @param monad_set_name the name of the monad set to use. If
 * "monads", then the monad set of which the object consists is
 * used. Otherwise, the string must refer to a feature on the object
 * type which is a set of monads.
 *
 * @param objectRangeType the eObjectRangeType of the object type
 *
 * @param largest_object_length the length (in monads) of the longest
 * object in the object type which we are querying.
 *
 * @param Result the Inst to get back.
 *
 * @return true on no DB error, false otherwise.
 */
bool BPTEMdFDB::getInstLocalBPT(const std::string& object_type_name,
				id_d_t object_type_id,
				const SetOfMonads& Su,
				const SetOfMonads& all_m_1,
				EMdFFFeatures *pre_query_constraints,
				const std::list<FeatureInfo>& features_to_get,
				const std::string& monad_set_name,
				eObjectRangeType objectRangeType,
				eMonadSetRelationOperation ms_operation,
				/* out */ Inst& Result)
{
	if (pConn == 0)
		return false;
	else {
		// ****************************************************
		//
		// Preliminaries
		//
		// ****************************************************

		// Are we doing a normal "monads" Inst or a "monad-set-feature" Inst
		std::string locase_monad_set_name;
		str_tolower(monad_set_name, locase_monad_set_name);

		bool bMonadSetIsFeature = strcmp_nocase(locase_monad_set_name, "monads") != 0;

		bool bDBHasMonadSetLengthColumn = ((BPTEMdFConnection*)pConn)->hasMonadSetLengthColumn();

		// Normalize object type name
		std::string OTN = normalizeOTName(object_type_name);

		// Make string of features to get
		std::list<std::string> columns_to_get;
		std::vector<bool> feature_is_monads_vec;


		columns_to_get.push_back("object_id_d");
		if (bMonadSetIsFeature) {
			columns_to_get.push_back(encodeFeatureNameBPT(locase_monad_set_name));
			columns_to_get.push_back("first_monad_mdf_" + locase_monad_set_name);
		} else if (objectRangeType == kORTSingleRange) {
			columns_to_get.push_back("first_monad");
			if (bDBHasMonadSetLengthColumn) {
				columns_to_get.push_back("som_length");
			} else {
				columns_to_get.push_back("last_monad");
			}
		} else if (objectRangeType == kORTMultipleRange) {
			columns_to_get.push_back("first_monad");
			columns_to_get.push_back("monads");
			if (bDBHasMonadSetLengthColumn) {
				columns_to_get.push_back("som_length");
			}
		} else if (objectRangeType == kORTSingleMonad) {
			columns_to_get.push_back("first_monad");
		} else {
			ASSERT_THROW(false, "Unknown objectRangeType:" + long2string(objectRangeType));
		}

		std::vector<id_d_t> column_types_vec;
		std::vector<StringSetCache*> string_set_caches_vec(features_to_get.size(), 0);
		std::list<FeatureInfo>::const_iterator ci(features_to_get.begin());
		std::list<FeatureInfo>::const_iterator cend(features_to_get.end());
		while (ci != cend) {
			// Get lowercase name
			std::string locase_name;
			str_tolower(ci->getName(), locase_name);
			std::string encoded_feature_name;
			bool bIsMonads = false;

			// Is it self?
			// TODO: We should check for computed status when we add
			// ability to do computed features.
			if (locase_name == "self") {
				columns_to_get.push_back("object_id_d");

				column_types_vec.push_back(FEATURE_TYPE_ID_D);

				feature_is_monads_vec.push_back(false);
			} else if (locase_name == "monads") {
				bIsMonads = true;
				encoded_feature_name = "monads";
				if (objectRangeType == kORTSingleRange) {
					columns_to_get.push_back("first_monad");
					if (bDBHasMonadSetLengthColumn) {
						columns_to_get.push_back("som_length");
					} else {
						columns_to_get.push_back("last_monad");
					}

					// column_types_vec is based
					// on columns, not
					// features. 
					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);
					column_types_vec.push_back(FEATURE_TYPE_INTEGER);

					feature_is_monads_vec.push_back(true);

				} else if (objectRangeType == kORTMultipleRange) {
					columns_to_get.push_back("first_monad");
					columns_to_get.push_back("monads");
					// column_types_vec is based
					// on columns, not
					// features. So we add an
					// extra one here, and do
					// another one outside the if
					// -statement
					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);
					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);
					if (bDBHasMonadSetLengthColumn) {
						columns_to_get.push_back("som_length");
						// column_types_vec
						// is based on
						// columns, not
						// features. So we add
						// an extra one here,
						// and do another one
						// outside the if
						// -statement
						column_types_vec.push_back(FEATURE_TYPE_INTEGER);
					}

					feature_is_monads_vec.push_back(true);

				} else if (objectRangeType == kORTSingleMonad) {
					columns_to_get.push_back("first_monad");

					column_types_vec.push_back(FEATURE_TYPE_SET_OF_MONADS);
				
					feature_is_monads_vec.push_back(true);
				} else {
					ASSERT_THROW(false, "Unknown objectRangeType:" + long2string(objectRangeType));
				}
			} else {
				encoded_feature_name = encodeFeatureName(locase_name);
				columns_to_get.push_back(encoded_feature_name);
				/*
				if (featureTypeIdIsFromSet(ci->getType())) {
					if (!loadStringSetIntoCacheBPT(OTN,
								    object_type_id,
								    locase_name)) {
						DEBUG_X_FAILED("BPTEMdFDB::getInstLocalBPT()", ("getting string set cache for " + OTN + "." + locase_name));
						return false;
					}
						
					StringSetCache *pSSC = m_string_sets_cache->getSSC(object_type_id, encodeFeatureName(locase_name));
					string_set_caches_vec[feature_names_index] = pSSC;
				}
				*/

				// Add type to column_types_vec	
				column_types_vec.push_back(ci->getType());
				
				feature_is_monads_vec.push_back(false);
				
				if (featureTypeIdIsSOM(ci->getType())
				    && !bIsMonads) {
					columns_to_get.push_back("first_monad_" + encoded_feature_name);
					column_types_vec.push_back(FEATURE_TYPE_INTEGER);
				}
			}

			// Advance iterators
			++ci;
		}

		int columns_to_get_before_pre_query_constraints = columns_to_get.size();
		if (pre_query_constraints != 0) {
			((BPTEMdFFFeatures*)pre_query_constraints)->addFeatures(columns_to_get, column_types_vec);
		}
		int columns_to_get_after_pre_query_constraints = columns_to_get.size();

		// ****************************************************
		//
		// Build and execute first query
		//
		// ****************************************************
		eQueryKind query_kind;
		switch (ms_operation) {
		case kMSROPartOf:
			query_kind = kQueryKindPartOf;
			break;
		case kMSROStartsIn:
			query_kind = kQueryKindStartsIn;
			break;
		default:
			ASSERT_THROW(false,
				     "ERROR: ms_operation is neither kMSROPartOf nor kMSROStartsIn, but " + long2string(ms_operation) + " in BPTEMdFDB::getInst().");
			query_kind = kQueryKindPartOf; // Fool some compilers into giving no warning.
			break;
		}

		LOG_WRITE_TIME("BPTEMdFDB::getInstLocalBPT", "Query starting.");
		if (!((BPTEMdFConnection*)pConn)->execQuery(OTN,
							    query_kind,
							    &Su,
							    monad_set_name,
							    columns_to_get,
							    pre_query_constraints)) {
			DEBUG_BPT_QUERY_FAILED("BPTEMdFDB::getInstLocalBPT", OTN, Su.toString(), joinList(", ", columns_to_get), "");
			return false;
		}

		LOG_WRITE_TIME("BPTEMdFDB::getInstLocalBPT", "Query finished.");
		int column_index;
		int no_of_features_to_get = features_to_get.size();


		LOG_WRITE_TIME("BPTEMdFDB::getInstLocalBPT", "Retrieval starting.");
		InstObject *pObj = 0;
		try {
			bool bMoreRows = pConn->hasRow();
			
			int feature_column_index;
			if (bMonadSetIsFeature) {
				feature_column_index = 3;
			} else if (objectRangeType == kORTSingleMonad) {
				feature_column_index = 2;
			} else if (objectRangeType == kORTSingleRange) {
				feature_column_index = 3;
			} else if (objectRangeType == kORTMultipleRange) {
				if (bDBHasMonadSetLengthColumn) {
					feature_column_index = 4;
				} else {
					feature_column_index = 3;
				}
			} else {
				ASSERT_THROW(false,
					     "Unknown objectRangeType.");
			}

			int no_of_feature_columns_to_get = columns_to_get.size() 
				- feature_column_index 
				- (columns_to_get_after_pre_query_constraints - columns_to_get_before_pre_query_constraints);
			while (bMoreRows) {
				// Declare this pFeature_values array of dummy EMdFValue objects.
				EMdFValue *pFeature_values;
				if (no_of_features_to_get > 0) {
					// This uses the () constructor, which gives us a kEVInt with 
					// value 0.
					pFeature_values = (EMdFValue *) Result.allocate(sizeof(EMdFValue)*no_of_features_to_get);
				} else {
					pFeature_values = 0;
				}

				// Get object id_d
				id_d_t oid;
				if (!pConn->accessTuple(0, oid)) {
					DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
					return false;
				}

				// Get monads 
				SetOfMonads *pSom = 0; 
				monad_m mse_first, mse_last;
				// Get mse_first
				// std::cerr << "UP399: oid = " << oid << ", mse_first = " << mse_first << '\n';
				if (bMonadSetIsFeature) {
					std::string monads_string;
					if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(1, monads_string)) {
						DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
						return false;
					}
					long som_first_monad;
					if (!pConn->accessTuple(2, som_first_monad)) {
						DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
						return false;
					}
					pSom = new SetOfMonads();
					// std::cerr << "UP239: som_first_monad = '" << som_first_monad << ", monads_string = '" << monads_string << "'" << std::endl;
					pSom->fromCompactStringFM(monads_string, som_first_monad);
					// std::cerr << "UP239.2: pSom = " << pSom->toString() << std::endl;
					mse_first = pSom->first();
					mse_last = pSom->last();

					// std::cerr << "UP430: pSOM = " << pSom->toString() << ", first = " << pSom->first() << ", mse_first = " << mse_first << ", last = " << pSom->last() << '\n';


				} else {	
					if (!pConn->accessTuple(1, mse_first)) {
						DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
						return false;
					}

					if (objectRangeType == kORTMultipleRange) {
						if (bDBHasMonadSetLengthColumn) {
							monad_m som_length;
							if (!pConn->accessTuple(3, som_length)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
								return false;
							}
							// For
							// kORTMultipleRange
							// objects, the
							// som_length is
							// either 0 (because
							// we need to consult
							// the monads string),
							// or it is the true
							// length + 1, and so
							// we need to subtract
							// 1.

							if (som_length == 0) {
								std::string monads_string;
								if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(2, monads_string)) {	
									DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
									return false;
								}
								pSom = new SetOfMonads(monads_string, mse_first);
								mse_last = pSom->last();
							} else {
								// som_length != 0, so we can skip reading monads_string.
								mse_last = mse_first + som_length - 1;
								pSom = new SetOfMonads(mse_first, mse_last);
							}
						} else {
							std::string monads_string;
							if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(2, monads_string)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
								return false;
							}
							pSom = new SetOfMonads(monads_string, mse_first);
							mse_last = pSom->last();
							// std::cerr << "UP430: pSOM = " << pSom->toString() << ", first = " << pSom->first() << ", mse_first = " << mse_first << ", last = " << pSom->last() << '\n';
						}
					} else if (objectRangeType == kORTSingleMonad) {
						/* If this is WITH SINGLE MONAD OBJECTS, then we don't 
						 * retrive mse_last.  Instead, we just get it
						 * from mse_first.
						 */
						mse_last = mse_first;
					} else if (objectRangeType == kORTSingleRange) {
						if (bDBHasMonadSetLengthColumn) {
							monad_m som_length;
							if (!pConn->accessTuple(2, som_length)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
								return false;
							}
							// For kORTSingleRange
							// objects, the
							// som_length is the
							// true length, and so
							// we don't need to
							// subtract 1.
							
							mse_last = mse_first + som_length;
						} else {
							if (!pConn->accessTuple(2, mse_last)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
								return false;
							}
							// std::cerr << "UP440: mse_first = " << mse_first << ", last = " << mse_last << '\n';
						}
					} else {
						ASSERT_THROW(false, "Unknown objectRangeType:" + long2string(objectRangeType));
					}
				}

				// std::cerr << "UP420: mse_first = " << mse_first << ", mse_last = " << mse_last << '\n';

				// Get feature values
				if (no_of_features_to_get > 0) {
					std::string value_str;
					long value_long;
					int feature_index = 0;
					for (column_index = 0; column_index < no_of_feature_columns_to_get; ++column_index, ++feature_index) {
						id_d_t column_type = column_types_vec[column_index];
						if (featureTypeIdIsListOf(column_type)) {
							if (!pConn->accessTuple(feature_column_index + column_index, 
										value_str)) {
								DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
								delete pSom;
								return false;
							}
							IntegerList *pIntegerList = new IntegerList(value_str, DEFAULT_LIST_DELIMITER);
							switch (column_type & FEATURE_TYPE_TYPE_MASK) {
							case FEATURE_TYPE_LIST_OF_INTEGER:
								new (&pFeature_values[feature_index]) EMdFValue(kEVListOfInteger, pIntegerList);
								break;
							case FEATURE_TYPE_LIST_OF_ID_D:
								new (&pFeature_values[feature_index]) EMdFValue(kEVListOfID_D, pIntegerList);
								break;
							case FEATURE_TYPE_LIST_OF_ENUM:
								// We do not translate to enum constants, since this is done in the MQL layer.
								new (&pFeature_values[feature_index]) EMdFValue(kEVListOfInteger, pIntegerList);
								break;
							default:
								ASSERT_THROW(false, "Unknown FEATURE_TYPE");
								break;
							}
						} else {
							switch (column_type & FEATURE_TYPE_TYPE_MASK) {
							case FEATURE_TYPE_ASCII:
							case FEATURE_TYPE_STRING:
								if (!pConn->accessTuple(feature_column_index + column_index, 
											value_str)) {
									DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
									delete pSom;
									return false;
								}
								/*
								if (featureTypeIdIsFromSet(column_type)
								    && string_set_caches_vec[feature_index] != 0) {
									std::string newValue;
									id_d_t id_d = string2long(value_str);
									if (!string_set_caches_vec[feature_index]->getStringFromID_D(id_d, newValue)) {
										DEBUG_X_FAILED("BPTEMdFDB::getInstLocalBPT", "Getting string from set.");
										pConn->finalize();
										delete pSom;
										return false;
									}
									new (&pFeature_values[feature_index]) EMdFValue(newValue);
								} else {
								*/
								new (&pFeature_values[feature_index]) EMdFValue(value_str);
								/*
								}
								*/
								break;
							case FEATURE_TYPE_INTEGER:
								if (!pConn->accessTuple(feature_column_index + column_index, 
											value_long)) {
									DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
									delete pSom;
									return false;
								}
								new (&pFeature_values[feature_index]) EMdFValue(kEVInt, value_long);
								break;
							case FEATURE_TYPE_ID_D:
								if (!pConn->accessTuple(feature_column_index + column_index, 
											value_long)) {
									DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
									delete pSom;
									return false;
								}
								new (&pFeature_values[feature_index]) EMdFValue(kEVID_D, value_long);
								break;
							case FEATURE_TYPE_SET_OF_MONADS:
								if (feature_is_monads_vec[feature_index]) {
									SetOfMonads som;
									
									monad_m feature_mse_first;
									
									if (!pConn->accessTuple(feature_column_index + column_index, feature_mse_first)) {
										DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
										delete pSom;
										return false;
									}
									
									
									if (objectRangeType == kORTSingleMonad) {
										/* If this is WITH SINGLE MONAD OBJECTS, then we don't 
										 * retrive mse_last.  Instead, we just get it
										 * from mse_first.
										 */
										som.add(feature_mse_first);
									} else if (objectRangeType == kORTSingleRange) {

										monad_m feature_mse_last;
										if (bDBHasMonadSetLengthColumn) {
											monad_m feature_som_length;
											++column_index;
											if (!pConn->accessTuple(feature_column_index + column_index, feature_som_length)) {
												DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
												return false;
											}
											// For kORTSingleRange
											// objects, the
											// som_length is the
											// true length, and so
											// we don't need to
											// subtract 1.
											
											feature_mse_last = feature_mse_first + feature_som_length;
										} else {
											++column_index;
											if (!pConn->accessTuple(feature_column_index + column_index, feature_mse_last)) {
												DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
												delete pSom;
												return false;
											}
										}
										som.add(feature_mse_first, feature_mse_last);
									} else if (objectRangeType == kORTMultipleRange) {
										if (bDBHasMonadSetLengthColumn) {
											monad_m feature_som_length;
											++column_index;
											if (!pConn->accessTuple(feature_column_index + column_index + 1, feature_som_length)) {
												DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
												return false;
											}
											// For
											// kORTMultipleRange
											// objects, the
											// som_length is
											// either 0 (because
											// we need to consult
											// the monads string),
											// or it is the true
											// length + 1, and so
											// we need to subtract
											// 1.
											
											if (feature_som_length == 0) {
												std::string feature_monads_string;
												if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(feature_column_index + column_index, feature_monads_string)) {
													DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsHavingMonadsInMonadSet");
													return false;
												}
												som.fromCompactStringFM(feature_monads_string, feature_mse_first);
											} else {
												// som_length != 0, so we can skip reading monads_string.
												monad_m feature_mse_last = feature_mse_first + feature_som_length - 1;
												som.add(feature_mse_first, feature_mse_last);
											}
											++column_index;
										} else {
											std::string monads_string;
											++column_index;
											if (!((BPTEMdFConnection *)pConn)->accessMonadSetTuple(feature_column_index + column_index, monads_string)) {
												DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
												delete pSom;
												return false;
											}
											som.fromCompactStringFM(monads_string, feature_mse_first);
										}
									} else {
										ASSERT_THROW(false, "Unknown objectRangeType:" + long2string(objectRangeType));
									}

									new (&pFeature_values[feature_index]) EMdFValue(som);
								} else {
									if (!pConn->accessTuple(feature_column_index + column_index, 
												value_str)) {
										DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
										return false;
									}
									if (!pConn->accessTuple(feature_column_index + column_index + 1, 
												value_long)) {
										DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
										return false;
									}
									{
										SetOfMonads som;
										som.fromCompactStringFM(value_str, value_long);
										// std::cerr << "UP365: som = " << som.toString() << std::endl;
										new (&pFeature_values[feature_index]) EMdFValue(som);
										// std::cerr << "UP367!" << std::endl;
									}
									// Skip over the first_monad_mdf_<feature-name> column
									++column_index;
								}
								break;
							case FEATURE_TYPE_ENUM:
								if (!pConn->accessTuple(feature_column_index + column_index, 
											value_long)) {
									DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
									delete pSom;
									return false;
								}
								new (&pFeature_values[feature_index]) EMdFValue(kEVEnum, value_long);
								break;
							default:
								delete pSom;
								ASSERT_THROW(false, "Unknown FEATURE_TYPE.");
								break;
							}
						}
					}
				}

				// Make new object
				// First allocate using Result Inst's allocator
				pObj = (InstObject*) Result.allocate(sizeof(InstObject));
				if (bMonadSetIsFeature
				    || objectRangeType == kORTMultipleRange) {
					if (pSom->hasOnlyOneMSE()) {
						// Then use placement new operator (p. 255 in TC++PL 3rd ed.)
						// std::cerr << "UP502: About to create InstObject(" << mse_first << ", " << mse_last << ")\n";
						pObj = new(pObj) InstObject(oid, 
									    mse_first, mse_last,
									    pFeature_values, 
									    no_of_features_to_get); 
						delete pSom;
					} else {
						// Then use placement new operator (p. 255 in TC++PL 3rd ed.)
						// std::cerr << "UP503a: About to create InstObject(" << pSom->toString() << ")\n";
						pObj = new(pObj) InstObject(oid, 
									    pSom, 
									    pFeature_values, 
									    no_of_features_to_get,
									    false); 
					} 
				} else {
					// Then use placement new operator (p. 255 in TC++PL 3rd ed.)
					// std::cerr << "UP504: About to create InstObject(" << mse_first << ", " << mse_last << ")\n";
					pObj = new(pObj) InstObject(oid, 
								    mse_first, mse_last,
								    pFeature_values, 
								    no_of_features_to_get); 
				}
				
				// Insert object in inst
				Result.addObject(pObj, mse_first, mse_last);


				// Get next tuple
				// std::cerr << "UP492: About to call pConn->getNextTuple() from BPTEMdFDB::getInstLocalBPT" << std::endl;
				if (!pConn->getNextTuple(bMoreRows)) {
					DEBUG_GET_NEXT_TUPLE_FAILED("BPTEMdFDB::getInstLocalBPT");
					return false;
				}
			} // end of iteration over query-results
		} catch (EMdFNULLValueException e) {
			DEBUG_NULL_VALUE_EXCEPTION("BPTEMdFDB::getInstLocalBPT");
			// There was a NULL value exception, hence we return an error
			return false;
		}

		// Write "retrieval finished" to log
		LOG_WRITE_TIME("BPTEMdFDB::getInstLocalBPT", "Retrieval finished.");
		
		// Release results
		pConn->finalize();

		// finalize Result
		Result.fillingIsDone();

		// If we got this far, the command was as success.
		return true;
	}
}



/** Get the objects starting at a given monad Sm
 *@internal
 *
 * @param object_type_name The name of the object type which holds the
 * objects to query.
 *
 * @param Sm the monad at which to find the objects
 *
 * @param Result the IDDList which will contain the id_ds of the
 * objects at monad Sm.
 *
 * @return true on no DB error, false otherwise.
 */
bool BPTEMdFDB::getObjectsStartingAtSm(const std::string& object_type_name,
				       monad_m Sm,
				       /* out */ IDDList& Result)
{
	if (pConn == 0)
		return false;
	else {
		// Normalize object type name
		std::string OTN = normalizeOTName(object_type_name);

		// Build query
		std::list<std::string> columns_to_get;
		columns_to_get.push_back("object_id_d");

		SetOfMonads som(Sm);

		// Execute query
		if (!((BPTEMdFConnection*)pConn)->execQuery(OTN,
							    kQueryKindStartMonad,
							    &som,
							    "monads",
							    columns_to_get,
							    0)) {
			DEBUG_BPT_QUERY_FAILED("BPTEMdFDB::getObjectsStartingAtSm", OTN, som.toString(), joinList(", ", columns_to_get), "");
			return false;
		}
      
		try {
			bool bMoreRows = pConn->hasRow();
			while (bMoreRows) {
				id_d_t oid;
				if (!pConn->accessTuple(0, oid)) {
					DEBUG_ACCESS_TUPLE_FAILED("BPTEMdFDB::getObjectsStartingAtSm");
					return false;
				} else {
					Result.addOid(oid);
				}

				// Get next tuple
				if (!pConn->getNextTuple(bMoreRows)) {
					DEBUG_GET_NEXT_TUPLE_FAILED("BPTEMdFDB::getObjectsStartingAtSm");
					return false;
				}
			}
		} catch (EMdFNULLValueException e) {
			DEBUG_NULL_VALUE_EXCEPTION("BPTEMdFDB::getObjectsStartingAtSm");
			// There was a NULL value exception, hence we return an error
			return false;
		}
    
		// Release results
		pConn->finalize();

		// If we got this far, the command was as success.
		return true;
	}
}

//
// Gets the set of monads making up the object 
// with id_d object_id_d
//
/** Get the monads of an object with a given id_d
 *@internal
 *
 * @param object_id_d the id_d of the object to query
 *
 * @param object_type_id the object type id of the object type holding
 * the object.
 *
 * @param monads The SetOfMonads which will hold the object's monads.
 *
 * @return true on no DB error, false otherwise.
 */
bool BPTEMdFDB::getMonadsFromID_D(id_d_t object_id_d, 
				  id_d_t object_type_id,
				  /* out */ SetOfMonads& monads)
{
	// Get object type name
	std::string object_type_name;
	bool bObjectTypeExists;
	eObjectRangeType objectRangeType;
	eMonadUniquenessType monadUniquenessType;
	if (!objectTypeExists(object_type_id, 
			      bObjectTypeExists, 
			      object_type_name, 
			      objectRangeType,
			      monadUniquenessType)) {
		DEBUG_X_IS_WRONG("getMonadsFromID_D", 
				 "Could not get object type name for object id_d " 
				 + id_d2string(object_id_d) + ".\n");
		return false;
	}
	if (!bObjectTypeExists) {
		DEBUG_X_IS_WRONG("getMonadsFromID_D", 
				 "Object type for object with object id_d " 
				 + id_d2string(object_id_d) + " does not exist.\n");
		return true;
	}

	// Get set of monads
	if (!getSOMForObject(object_type_name, 
			     object_id_d, 
			     objectRangeType, 
			     monads)) {
		DEBUG_X_IS_WRONG("getMonadsFromID_D", 
				 "Could not getSOMForObject for object with object id_d " 
				 + id_d2string(object_id_d) + ".\n");
		return false;
	}

	// If we got this far, there were no errors
	return true;
}

