bool BPTEMdFDB::getStringOffset(const std::string& object_type_name,
				const std::string& feature_name,
				const std::string& instr,
				long& out_offset)
{
	std::string OTN = normalizeOTName(object_type_name);
	std::string encoded_feature_name = encodeFeatureName(feature_name);
	return ((BPTEMdFConnection*)pConn)->getStringOffset(object_type_name,
							    encoded_feature_name,
							    instr,
							    out_offset);
}

bool BPTEMdFDB::getStringSetStrings(const std::string& object_type_name, 
				    id_d_t object_type_id,
				    const std::string& feature_name,
				    /* out */ Table& result)
{
	if (!loadStringSetIntoCacheBPT(object_type_name,
				       object_type_id,
				       feature_name,
				       &result)) {
		DEBUG_X_FAILED("EMdFDB::getStringSetStrings", "loading all strings into cache.");
		return false;
	}
	return true;		
}

