void Expression::weed(MQLExecEnv *pEE, bool& bResult)
{
	if (m_type == kExprSetOfMonads) {
		if (m_pMQLMSE != 0) {
			m_pSOM = new SetOfMonads();
			m_pMQLMSE->weed(pEE, true, bResult);
			if (!bResult) {
				return;
			}
			m_pMQLMSE->monadsBuildSet(*m_pSOM);
			delete m_pMQLMSE;
			m_pMQLMSE = 0;
		} else if (m_pSOM == 0) {
			m_pSOM = new SetOfMonads();
		}
	}
}

