void disposeOfObjectSpecNoOT(ObjectSpecNoOT **ppHead)
{
	ObjectSpecNoOT *pToDelete = *ppHead;
	ObjectSpecNoOT *pOS = pToDelete, *pNext;
	while (pOS != 0) {
		pNext = pOS->getNext();
		delete pOS;
		pOS = pNext;
	}

	// Finally, set the original pointer to 0.
	*ppHead = 0;
}



