#if MQLYYSTACKDEPTH<=0
/*
** Try to increase the size of the parser stack.
*/
static void mqlyyGrowStack(mqlyyParser *p){
  int newSize;
  mqlyyStackEntry *pNew;

  newSize = p->mqlyystksz*2 + 100;
  pNew = realloc(p->mqlyystack, newSize*sizeof(pNew[0]));
  if( pNew ){
    p->mqlyystack = pNew;
    p->mqlyystksz = newSize;
#ifndef NDEBUG
    if( mqlyyTraceFILE ){
      fprintf(mqlyyTraceFILE,"%sStack grows to %d entries!\n",
              mqlyyTracePrompt, p->mqlyystksz);
    }
#endif
  }
}
#endif

/* 
** This function allocates a new parser.
** The only argument is a pointer to a function which works like
** malloc.
**
** Inputs:
** A pointer to the function used to allocate memory.
**
** Outputs:
** A pointer to a parser.  This pointer is used in subsequent calls
** to MQLParser and MQLParserFree.
*/
void *MQLParserAlloc(void *(*mallocProc)(size_t)){
  mqlyyParser *pParser;
  pParser = (mqlyyParser*)(*mallocProc)( (size_t)sizeof(mqlyyParser) );
  if( pParser ){
    pParser->mqlyyidx = -1;
#ifdef MQLYYTRACKMAXSTACKDEPTH
    pParser->mqlyyidxMax = 0;
#endif
#if MQLYYSTACKDEPTH<=0
    pParser->mqlyystack = NULL;
    pParser->mqlyystksz = 0;
    mqlyyGrowStack(pParser);
#endif
  }
  return pParser;
}

