/*
** Pop the parser's stack once.
**
** If there is a destructor routine associated with the token which
** is popped from the stack, then call it.
**
** Return the major token number for the symbol popped.
*/
static int mqlyy_pop_parser_stack(mqlyyParser *pParser){
  MQLYYCODETYPE mqlyymajor;
  mqlyyStackEntry *mqlyytos = &pParser->mqlyystack[pParser->mqlyyidx];

  if( pParser->mqlyyidx<0 ) return 0;
#ifndef NDEBUG
  if( mqlyyTraceFILE && pParser->mqlyyidx>=0 ){
    fprintf(mqlyyTraceFILE,"%sPopping %s\n",
      mqlyyTracePrompt,
      mqlyyTokenName[mqlyytos->major]);
  }
#endif
  mqlyymajor = mqlyytos->major;
  mqlyy_destructor(pParser, mqlyymajor, &mqlyytos->minor);
  pParser->mqlyyidx--;
  return mqlyymajor;
}

/* 
** Deallocate and destroy a parser.  Destructors are all called for
** all stack elements before shutting the parser down.
**
** Inputs:
** <ul>
** <li>  A pointer to the parser.  This should be a pointer
**       obtained from MQLParserAlloc.
** <li>  A pointer to a function used to reclaim memory obtained
**       from malloc.
** </ul>
*/
void MQLParserFree(
  void *p,                    /* The parser to be deleted */
  void (*freeProc)(void*)     /* Function used to reclaim memory */
){
  mqlyyParser *pParser = (mqlyyParser*)p;
  if( pParser==0 ) return;
  while( pParser->mqlyyidx>=0 ) mqlyy_pop_parser_stack(pParser);
#if MQLYYSTACKDEPTH<=0
  free(pParser->mqlyystack);
#endif
  (*freeProc)((void*)pParser);
}

/*
** Return the peak depth of the stack for a parser.
*/
#ifdef MQLYYTRACKMAXSTACKDEPTH
int MQLParserStackPeak(void *p){
  mqlyyParser *pParser = (mqlyyParser*)p;
  return pParser->mqlyyidxMax;
}
#endif

