{
	if (isFFactor()) {
		// fterm ::= ffactor
		return m_ffactor->exec(pEE, pInstObj);
	} else {
		// fterm ::= fterm "AND" ffactor
		if (!m_fterm->exec(pEE, pInstObj))
			return false;
		
		return m_ffactor->exec(pEE, pInstObj);
	}
}

