void TemplateIf::exec(TemplateLangExecEnv *pEE)
{
	TemplateASTNode::exec(pEE);

	m_pCondition->exec(pEE);
	if (pEE->bLastIfCondition) {
		if (m_pExecIfTrue != 0) {
			m_pExecIfTrue->exec(pEE);
		}
	} else {	
		if (m_pExecIfFalse != 0) {
			m_pExecIfFalse->exec(pEE);
		}
	}
}




