#if TMPLGYYSTACKDEPTH<=0
/*
** Try to increase the size of the parser stack.
*/
static void tmplgyyGrowStack(tmplgyyParser *p){
  int newSize;
  tmplgyyStackEntry *pNew;

  newSize = p->tmplgyystksz*2 + 100;
  pNew = realloc(p->tmplgyystack, newSize*sizeof(pNew[0]));
  if( pNew ){
    p->tmplgyystack = pNew;
    p->tmplgyystksz = newSize;
#ifndef NDEBUG
    if( tmplgyyTraceFILE ){
      fprintf(tmplgyyTraceFILE,"%sStack grows to %d entries!\n",
              tmplgyyTracePrompt, p->tmplgyystksz);
    }
#endif
  }
}
#endif

/* 
** This function allocates a new parser.
** The only argument is a pointer to a function which works like
** malloc.
**
** Inputs:
** A pointer to the function used to allocate memory.
**
** Outputs:
** A pointer to a parser.  This pointer is used in subsequent calls
** to TemplateLangParser and TemplateLangParserFree.
*/
void *TemplateLangParserAlloc(void *(*mallocProc)(size_t)){
  tmplgyyParser *pParser;
  pParser = (tmplgyyParser*)(*mallocProc)( (size_t)sizeof(tmplgyyParser) );
  if( pParser ){
    pParser->tmplgyyidx = -1;
#ifdef TMPLGYYTRACKMAXSTACKDEPTH
    pParser->tmplgyyidxMax = 0;
#endif
#if TMPLGYYSTACKDEPTH<=0
    pParser->tmplgyystack = NULL;
    pParser->tmplgyystksz = 0;
    tmplgyyGrowStack(pParser);
#endif
  }
  return pParser;
}

