#define MYSIGN(A) ((A == 0) ? 0 : ((A < 0) ? -1 : 1))
#define MYABS(A) ((A < 0) ? -A : A)

#define MYMAX(A,B) ((A > B) ? (A) : (B))
#define MYMIN(A,B) ((A < B) ? (A) : (B))


