/******************************************************************
 *
 * Utility functions
 *
 ******************************************************************/

bool executeQuery_FTS3Search(EmdrosEnv *pEE, const std::string& query)
{
	bool bCompilerSuccess = false;
	bool bDBSuccess = pEE->executeString(query,
					     bCompilerSuccess,
					     false,
					     false);
	return bCompilerSuccess && bDBSuccess;
}



